public build(): CodeGraph {
    // Clear all maps for fresh graph generation
    this.functions.clear();
    this.variables.clear();
    this.globalVariableIdsByFile.clear();
    this.externalModules.clear();
    this.importedExternalSymbolsByFile.clear();
    this.calls = [];

    // Get TypeScript files for AST parsing
    const files = this.getAllTypeScriptFiles(this.sourceDir);
    const htmlFiles = this.getAllHtmlFiles(this.sourceDir);

    if (files.length === 0) {
      throw new Error(`No TypeScript files found in ${this.sourceDir}`);
    }

    console.log(`📊 Scanning ${files.length} TypeScript files...`);

    // TWO-PASS APPROACH
    // Pass 1: Extract all function and variable declarations
    const sourceFiles: Array<{ filePath: string; sourceFile: ts.SourceFile; source: string }> = [];
    const parseErrors: Array<{ filePath: string; error: string }> = [];

    for (const filePath of files) {
      try {
        const source = fs.readFileSync(filePath, 'utf-8');
        const sourceFile = ts.createSourceFile(
          filePath,
          source,
          ts.ScriptTarget.Latest,
          true
        );
        sourceFiles.push({ filePath, sourceFile, source });
        this.visitDeclarations(sourceFile, filePath);
      } catch (error) {
        const errorMsg = error instanceof Error ? error.message : String(error);
        parseErrors.push({ filePath, error: errorMsg });
        console.error(`❌ Failed to parse ${filePath}: ${errorMsg}`);
      }
    }

    // If critical files failed to parse, the graph is incomplete
    if (parseErrors.length > 0) {
      const errorSummary = parseErrors.map(e => `  - ${e.filePath}: ${e.error}`).join('\n');
      throw new Error(
        `Failed to parse ${parseErrors.length} file(s). Graph is incomplete:\n${errorSummary}`
      );
    }

    // Pass 2: Extract all function calls
    for (const { filePath, sourceFile } of sourceFiles) {
      this.visitCalls(sourceFile, filePath);
    }

    // Pass 3: Add HTML entry nodes and connect to referenced scripts.
    for (const htmlFile of htmlFiles) {
      this.visitHtmlEntry(htmlFile);
    }

    const nodes: CodeNode[] = [
      ...Array.from(this.functions.values()),
      ...Array.from(this.variables.values()),
      ...Array.from(this.externalModules.values())
    ];

    // Keep file inventory aligned with parsed source files only.
    const projectFiles = Array.from(new Set([
      ...files.map((f) => path.relative(this.sourceDir, f).replace(/\\/g, '/')),
      ...htmlFiles.map((f) => path.relative(this.sourceDir, f).replace(/\\/g, '/')),
    ])).sort();

    console.log(`✓ Extracted ${this.functions.size} functions, ${this.variables.size} variables, ${this.externalModules.size} external modules`);
    console.log(`✓ Identified ${this.calls.length} function calls`);

    return {
      nodes,
      edges: this.calls,
      files: projectFiles,
      lastUpdated: new Date().toISOString()
    };
  }

private shouldIgnorePath(fullPath: string): boolean {
    const normalized = fullPath.replace(/\\+/g, '/');
    const parts = normalized.split('/');
    if (parts.includes('node_modules') || parts.includes('.git') || parts.includes('dist') || parts.includes('coverage')) {
      return true;
    }
    // public/ contains static assets and cached copies of source files — skip to avoid duplicates.
    if (parts.includes('public')) {
      return true;
    }
    return false;
  }

private getAllProjectFiles(dir: string): string[] {
    const files: string[] = [];

    const walkDir = (currentPath: string) => {
      if (this.shouldIgnorePath(currentPath)) {
        return;
      }

      const entries = fs.readdirSync(currentPath, { withFileTypes: true });
      for (const entry of entries) {
        const fullPath = path.join(currentPath, entry.name);
        if (this.shouldIgnorePath(fullPath)) {
          continue;
        }

        if (entry.isDirectory()) {
          walkDir(fullPath);
        } else {
          // Only include source code file types — skip markdown, JSON, images, logs, etc.
          const ext = path.extname(entry.name).toLowerCase();
          if (['.ts', '.tsx', '.js', '.jsx', '.mts', '.mjs', '.cjs'].includes(ext)) {
            files.push(path.relative(this.sourceDir, fullPath).replace(/\\/g, '/'));
          }
        }
      }
    };

    walkDir(dir);
    return files.sort();
  }

private getAllTypeScriptFiles(dir: string): string[] {
    const files: string[] = [];

    const walkDir = (currentPath: string) => {
      const entries = fs.readdirSync(currentPath, { withFileTypes: true });

      for (const entry of entries) {
        const fullPath = path.join(currentPath, entry.name);

        if (this.shouldIgnorePath(fullPath)) {
          continue;
        }

        if (entry.isDirectory()) {
          if (!entry.name.startsWith('.')) {
            walkDir(fullPath);
          }
        } else if (entry.name.endsWith('.ts') && !entry.name.endsWith('.spec.ts')) {
          files.push(fullPath);
        }
      }
    };

    walkDir(dir);
    return files;
  }

private getAllHtmlFiles(dir: string): string[] {
    const files: string[] = [];

    const walkDir = (currentPath: string) => {
      const entries = fs.readdirSync(currentPath, { withFileTypes: true });

      for (const entry of entries) {
        const fullPath = path.join(currentPath, entry.name);

        if (this.shouldIgnorePath(fullPath)) {
          continue;
        }

        if (entry.isDirectory()) {
          if (!entry.name.startsWith('.')) {
            walkDir(fullPath);
          }
        } else if (entry.name.endsWith('.html')) {
          files.push(fullPath);
        }
      }
    };

    walkDir(dir);
    return files;
  }

private visitHtmlEntry(filePath: string): void {
    const relative = path.relative(this.sourceDir, filePath).replace(/\\/g, '/');
    const id = `html:${relative}`;

    let source = '';
    try {
      source = fs.readFileSync(filePath, 'utf-8');
    } catch {
      return;
    }

    if (!this.functions.has(id)) {
      this.functions.set(id, {
        id,
        name: relative,
        file: relative,
        line: 1,
        isExported: true,
        type: 'function',
        code: this.extractTextPreview(source, 12000),
      });
    }

    const scriptRefs = this.extractHtmlScriptSources(source)
      .map((ref) => this.normalizeHtmlScriptReference(ref, relative))
      .filter((ref): ref is string => !!ref);

    for (const scriptRef of scriptRefs) {
      const targets = Array.from(this.functions.entries())
        .filter(([fnId, fn]) => fnId !== id && fn.file === scriptRef && fn.type === 'function')
        .sort((a, b) => (a[1].isExported === b[1].isExported ? a[1].name.localeCompare(b[1].name) : (a[1].isExported ? -1 : 1)));

      if (targets.length === 0) {
        continue;
      }

      // Prefer exported entries for navigation; fall back to first discovered function.
      const preferred = targets.filter(([, fn]) => fn.isExported);
      const selectedTargets = preferred.length > 0 ? preferred : [targets[0]];
      for (const [targetId] of selectedTargets) {
        this.addEdge(id, targetId, 'call');
      }
    }
  }

private extractHtmlScriptSources(source: string): string[] {
    const results: string[] = [];
    const scriptRegex = /<script\b[^>]*\bsrc\s*=\s*['\"]([^'\"]+)['\"][^>]*>/gi;
    let match: RegExpExecArray | null = null;
    while ((match = scriptRegex.exec(source)) !== null) {
      const src = (match[1] || '').trim();
      if (src) {
        results.push(src);
      }
    }
    return results;
  }

private normalizeHtmlScriptReference(rawRef: string, htmlRelativePath: string): string | null {
    if (!rawRef || /^https?:\/\//i.test(rawRef) || rawRef.startsWith('//')) {
      return null;
    }

    const noQuery = rawRef.split('?')[0].split('#')[0];
    if (!noQuery) {
      return null;
    }

    const htmlDir = path.posix.dirname(htmlRelativePath.replace(/\\/g, '/'));
    const baseDir = htmlDir === '.' ? '' : htmlDir;
    const normalized = noQuery.startsWith('/')
      ? noQuery.slice(1)
      : path.posix.normalize(path.posix.join(baseDir, noQuery));

    return normalized.replace(/^\.\//, '');
  }

private extractTextPreview(source: string, maxChars: number): string {
    const normalized = source.replace(/\r\n/g, '\n').trim();
    if (normalized.length <= maxChars) {
      return normalized;
    }
    return `${normalized.slice(0, maxChars)}\n<!-- ...truncated... -->`;
  }

private visitDeclarations(node: ts.Node, filePath: string): void {
    // Extract external module imports
    if (ts.isImportDeclaration(node) && node.moduleSpecifier && ts.isStringLiteral(node.moduleSpecifier)) {
      const moduleName = node.moduleSpecifier.text;
      // Only track external modules (not relative imports)
      if (!moduleName.startsWith('.')) {
        const id = `ext:${moduleName}`;
        if (!this.externalModules.has(id)) {
          this.externalModules.set(id, {
            id,
            name: moduleName,
            type: 'external'
          });
        }

        if (node.importClause) {
          // import fs from 'fs'
          if (node.importClause.name) {
            this.registerImportedExternalSymbol(filePath, node.importClause.name.text, id);
          }

          const namedBindings = node.importClause.namedBindings;
          if (namedBindings) {
            // import * as path from 'path'
            if (ts.isNamespaceImport(namedBindings)) {
              this.registerImportedExternalSymbol(filePath, namedBindings.name.text, id);
            }

            // import { readFileSync as read } from 'fs'
            if (ts.isNamedImports(namedBindings)) {
              for (const element of namedBindings.elements) {
                const localName = (element.propertyName ?? element.name).text;
                this.registerImportedExternalSymbol(filePath, localName, id);
              }
            }
          }
        }
      }
    }

    // Extract global variable declarations (top-level)
    if (ts.isVariableStatement(node) && node.parent && ts.isSourceFile(node.parent)) {
      const isExported = node.modifiers?.some(mod => mod.kind === ts.SyntaxKind.ExportKeyword) ?? false;

      for (const decl of node.declarationList.declarations) {
        if (decl.name && ts.isIdentifier(decl.name)) {
          const varName = decl.name.text;
          const lineNumber = this.getLineNumber(node, filePath);
          const id = `var:${varName}@${filePath}`;

          this.variables.set(id, {
            id,
            name: varName,
            file: path.relative(this.sourceDir, filePath).replace(/\\/g, '/'),
            line: lineNumber,
            isExported,
            type: 'variable'
          });
          this.registerGlobalVariable(filePath, varName, id);
        }
      }
    }

    // Extract function declarations
    if (ts.isFunctionDeclaration(node) && node.name) {
      const functionName = node.name.text;
      const lineNumber = this.getLineNumber(node, filePath);
      const id = `${functionName}@${filePath}`;
      const isExported = node.modifiers?.some(mod => mod.kind === ts.SyntaxKind.ExportKeyword) ?? false;

      this.functions.set(id, {
        id,
        name: functionName,
        file: path.relative(this.sourceDir, filePath).replace(/\\/g, '/'),
        line: lineNumber,
        isExported,
        type: 'function',
        code: this.extractFunctionCode(node)
      });
    }

    // Extract method declarations in classes
    if (ts.isMethodDeclaration(node) && node.name && typeof node.name === 'object') {
      const methodName = (node.name as any).text;
      const lineNumber = this.getLineNumber(node, filePath);
      const id = `${methodName}@${filePath}`;
      // Method is exported if it has export modifier OR if its parent class is exported
      const hasExportModifier = node.modifiers?.some(mod => mod.kind === ts.SyntaxKind.ExportKeyword) ?? false;
      const isPublicOrDefault = !(node.modifiers?.some(mod => mod.kind === ts.SyntaxKind.PrivateKeyword) ?? false);
      const parentClassExported = this.isMethodInExportedClass(node);
      const isExported = hasExportModifier || (parentClassExported && isPublicOrDefault);

      this.functions.set(id, {
        id,
        name: methodName,
        file: path.relative(this.sourceDir, filePath).replace(/\\/g, '/'),
        line: lineNumber,
        isExported,
        type: 'function',
        code: this.extractFunctionCode(node)
      });
    }

    // Extract arrow function methods in classes (e.g., private methodName = () => {})
    if (ts.isPropertyDeclaration(node) && node.name && ts.isIdentifier(node.name) && node.initializer && ts.isArrowFunction(node.initializer)) {
      const methodName = node.name.text;
      const lineNumber = this.getLineNumber(node, filePath);
      const id = `${methodName}@${filePath}`;
      // Property is exported if it has export modifier OR if its parent class is exported
      const hasExportModifier = node.modifiers?.some(mod => mod.kind === ts.SyntaxKind.ExportKeyword) ?? false;
      const isPublicOrDefault = !(node.modifiers?.some(mod => mod.kind === ts.SyntaxKind.PrivateKeyword) ?? false);
      const parentClassExported = this.isMethodInExportedClass(node);
      const isExported = hasExportModifier || (parentClassExported && isPublicOrDefault);

      this.functions.set(id, {
        id,
        name: methodName,
        file: path.relative(this.sourceDir, filePath).replace(/\\/g, '/'),
        line: lineNumber,
        isExported,
        type: 'function',
        code: this.extractFunctionCode(node)
      });
    }

    // Recurse through children
    ts.forEachChild(node, (child) => this.visitDeclarations(child, filePath));
  }

private registerImportedExternalSymbol(filePath: string, identifier: string, externalId: string): void {
    if (!identifier) {
      return;
    }

    if (!this.importedExternalSymbolsByFile.has(filePath)) {
      this.importedExternalSymbolsByFile.set(filePath, new Map());
    }
    this.importedExternalSymbolsByFile.get(filePath)!.set(identifier, externalId);
  }

private isMethodInExportedClass(node: ts.Node): boolean {
    let current = node.parent;
    while (current) {
      if (ts.isClassDeclaration(current)) {
        const hasExportModifier = current.modifiers?.some(mod => mod.kind === ts.SyntaxKind.ExportKeyword) ?? false;
        return hasExportModifier;
      }
      current = current.parent;
    }
    return false;
  }

private visitCalls(node: ts.Node, filePath: string): void {
    // Extract function calls
    if (ts.isCallExpression(node)) {
      const caller = this.findEnclosingFunction(node, filePath);
      const callee = this.getCalleeInfo(node);

      if (caller && callee) {
        const callerNode = this.functions.get(caller);
        const isObjectQualifiedSelfName = Boolean(
          callerNode
          && callee.receiverKind !== null
          && callee.receiverKind !== 'this'
          && callee.receiverKind !== 'super'
          && callerNode.name === callee.name,
        );

        if (isObjectQualifiedSelfName) {
          ts.forEachChild(node, (child) => this.visitCalls(child, filePath));
          return;
        }

        // Try to resolve the callee to a function we know about
        const resolvedCallee = this.resolveCalleeToFunction(callee.name, filePath);
        let resolvedTarget = resolvedCallee;
        if (!resolvedTarget) {
          resolvedTarget = this.resolveCalleeToExternalModule(callee, filePath);
        }

        if (resolvedTarget) {
          // Check if this edge already exists
          this.addEdge(caller, resolvedTarget, 'call');
        }
      }
    }

    if (ts.isIdentifier(node)) {
      this.recordVariableAccess(node, filePath);
    }

    // Recurse through children
    ts.forEachChild(node, (child) => this.visitCalls(child, filePath));
  }

private addEdge(from: string, to: string, kind: 'call' | 'var-read' | 'var-write' = 'call'): void {
    const edgeExists = this.calls.some(
      (edge) => edge.from === from && edge.to === to && (edge.kind ?? 'call') === kind,
    );
    if (edgeExists) {
      return;
    }
    this.calls.push({ from, to, kind });
  }

private registerGlobalVariable(filePath: string, variableName: string, variableId: string): void {
    if (!this.globalVariableIdsByFile.has(filePath)) {
      this.globalVariableIdsByFile.set(filePath, new Map());
    }
    this.globalVariableIdsByFile.get(filePath)!.set(variableName, variableId);
  }

private resolveGlobalVariableId(filePath: string, identifier: string): string | null {
    const fileMap = this.globalVariableIdsByFile.get(filePath);
    if (!fileMap) {
      return null;
    }
    return fileMap.get(identifier) ?? null;
  }

private recordVariableAccess(identifierNode: ts.Identifier, filePath: string): void {
    const variableId = this.resolveGlobalVariableId(filePath, identifierNode.text);
    if (!variableId) {
      return;
    }

    if (!this.isRuntimeVariableUsage(identifierNode)) {
      return;
    }

    const caller = this.findEnclosingFunction(identifierNode, filePath);
    if (!caller) {
      return;
    }

    const access = this.getVariableAccessKind(identifierNode);
    if (access.read) {
      this.addEdge(caller, variableId, 'var-read');
    }
    if (access.write) {
      this.addEdge(caller, variableId, 'var-write');
    }
  }

private isRuntimeVariableUsage(node: ts.Identifier): boolean {
    const parent = node.parent;
    if (!parent) {
      return false;
    }

    if (ts.isImportClause(parent)
      || ts.isImportSpecifier(parent)
      || ts.isNamespaceImport(parent)
      || ts.isImportEqualsDeclaration(parent)
      || ts.isExportSpecifier(parent)
      || ts.isTypeReferenceNode(parent)
      || ts.isInterfaceDeclaration(parent)
      || ts.isTypeAliasDeclaration(parent)
      || ts.isClassDeclaration(parent)
      || ts.isFunctionDeclaration(parent)
      || ts.isMethodDeclaration(parent)
      || ts.isParameter(parent)
      || ts.isVariableDeclaration(parent)
      || ts.isBindingElement(parent)
      || ts.isPropertySignature(parent)
      || ts.isEnumMember(parent)
      || ts.isTypeParameterDeclaration(parent)
      || ts.isQualifiedName(parent)) {
      return false;
    }

    if (ts.isPropertyAccessExpression(parent) && parent.name === node) {
      return false;
    }

    if (ts.isPropertyAssignment(parent) && parent.name === node) {
      return false;
    }

    return true;
  }

private getVariableAccessKind(node: ts.Identifier): { read: boolean; write: boolean } {
    const parent = node.parent;
    if (!parent) {
      return { read: true, write: false };
    }

    if (ts.isBinaryExpression(parent) && parent.left === node && this.isAssignmentOperator(parent.operatorToken.kind)) {
      const isSimpleAssign = parent.operatorToken.kind === ts.SyntaxKind.EqualsToken;
      return { read: !isSimpleAssign, write: true };
    }

    if (ts.isPrefixUnaryExpression(parent)
      && parent.operand === node
      && (parent.operator === ts.SyntaxKind.PlusPlusToken || parent.operator === ts.SyntaxKind.MinusMinusToken)) {
      return { read: true, write: true };
    }

    if (ts.isPostfixUnaryExpression(parent)
      && parent.operand === node
      && (parent.operator === ts.SyntaxKind.PlusPlusToken || parent.operator === ts.SyntaxKind.MinusMinusToken)) {
      return { read: true, write: true };
    }

    return { read: true, write: false };
  }

private getLineNumber(node: ts.Node, filePath: string): number {
    const source = fs.readFileSync(filePath, 'utf-8');
    const { line } = ts.getLineAndCharacterOfPosition(
      ts.createSourceFile(filePath, source, ts.ScriptTarget.Latest, true),
      node.getStart()
    );
    return line + 1;
  }

private findEnclosingFunction(node: ts.Node, filePath: string): string | null {
    let current = node.parent;

    while (current) {
      if (ts.isFunctionDeclaration(current) && current.name) {
        const id = `${current.name.text}@${filePath}`;
        if (this.functions.has(id)) {
          return id;
        }
      }

      if (ts.isMethodDeclaration(current) && current.name && typeof current.name === 'object') {
        const methodName = (current.name as any).text;
        const id = `${methodName}@${filePath}`;
        if (this.functions.has(id)) {
          return id;
        }
      }

      current = current.parent;
    }

    return null;
  }

private getCalleeInfo(node: ts.CallExpression): CalleeInfo | null {
    const expression = node.expression;

    if (ts.isIdentifier(expression)) {
      return {
        name: expression.text,
        receiverKind: null,
        receiverIdentifier: null,
      };
    }

    if (ts.isPropertyAccessExpression(expression)) {
      let receiverKind: CalleeInfo['receiverKind'] = 'other';
      if (expression.expression.kind === ts.SyntaxKind.ThisKeyword) {
        receiverKind = 'this';
      } else if (expression.expression.kind === ts.SyntaxKind.SuperKeyword) {
        receiverKind = 'super';
      } else if (ts.isIdentifier(expression.expression)) {
        receiverKind = 'identifier';
      }

      return {
        name: (expression.name as ts.Identifier).text,
        receiverKind,
        receiverIdentifier: ts.isIdentifier(expression.expression) ? expression.expression.text : null,
      };
    }

    return null;
  }

private resolveCalleeToExternalModule(callee: CalleeInfo, filePath: string): string | null {
    const importedSymbols = this.importedExternalSymbolsByFile.get(filePath);
    if (!importedSymbols) {
      return null;
    }

    // Direct identifier call, e.g. readFileSync(...)
    if (callee.receiverKind === null) {
      return importedSymbols.get(callee.name) ?? null;
    }

    // Property access on imported namespace/default, e.g. fs.readFileSync(...)
    if (callee.receiverKind === 'identifier' && callee.receiverIdentifier) {
      return importedSymbols.get(callee.receiverIdentifier) ?? null;
    }

    return null;
  }

private extractFunctionCode(node: ts.Node): string {
    try {
      const sourceFile = node.getSourceFile();
      const raw = node.getText(sourceFile);
      const normalized = raw.replace(/\r\n/g, '\n').trim();
      const maxChars = 12000;
      if (normalized.length <= maxChars) {
        return normalized;
      }
      return `${normalized.slice(0, maxChars)}\n/* ...truncated... */`;
    } catch {
      return '';
    }
  }

private resolveCalleeToFunction(calleeName: string, filePath: string): string | null {
    // First, try to find in the same file
    const sameFileMatches = Array.from(this.functions.entries()).filter(
      ([id, func]) => id.endsWith(filePath) && func.name === calleeName
    );

    if (sameFileMatches.length > 0) {
      return sameFileMatches[0][0];
    }

    // Then try to find in any file
    const anyFileMatches = Array.from(this.functions.entries()).filter(
      ([_, func]) => func.name === calleeName
    );

    if (anyFileMatches.length > 0) {
      return anyFileMatches[0][0];
    }

    return null;
  }

private shouldIgnoreFile(filename: string): boolean {
    const normalized = filename.replace(/\\+/g, '/');
    if (!normalized || normalized.startsWith('.')) return true;
    if (normalized.includes('/node_modules/') || normalized.startsWith('node_modules/')) return true;
    if (normalized.includes('/.git/') || normalized.startsWith('.git/')) return true;
    if (normalized.includes('/dist/') || normalized.startsWith('dist/')) return true;
    if (normalized.includes('/coverage/') || normalized.startsWith('coverage/')) return true;
    if (normalized === 'public/graph.json' || normalized === 'public/version.json') return true;
    return false;
  }

public watch(): void {
    console.log(`👀 Watching for changes in ${this.sourceDir}/...`);
    console.log('📊 Press Ctrl+C to stop\n');

    // Initial build
    this.rebuild();

    // Watch the directory
    fs.watch(this.sourceDir, { recursive: true }, (eventType, filename) => {
      if (!filename || this.shouldIgnoreFile(filename)) {
        return;
      }

      this.debounceRebuild();
    });
  }

private debounceRebuild(): void {
    // Clear existing timer
    if (this.debounceTimer) {
      clearTimeout(this.debounceTimer);
    }

    // Debounce rapid changes (300ms)
    this.debounceTimer = setTimeout(() => {
      this.rebuild();
    }, 300);
  }

private rebuild(): void {
    if (this.isProcessing) {
      return;
    }

    this.isProcessing = true;

    try {
      const startTime = Date.now();
      const nodeExecutable = process.execPath;
      const tsxCliPath = path.resolve('./node_modules/tsx/dist/cli.mjs');

      execFileSync(nodeExecutable, [tsxCliPath, path.resolve('./scripts/build-graph.ts')], {
        stdio: 'inherit',
        cwd: path.resolve(this.sourceDir),
      });

      const versionPath = path.resolve('./public/version.json');
      const version = JSON.parse(fs.readFileSync(versionPath, 'utf-8')) as {
        graphNodes?: number;
        graphEdges?: number;
      };
      const duration = Date.now() - startTime;

      console.log(
        `✅ [${new Date().toLocaleTimeString()}] Graph updated: ${version.graphNodes || 0} functions, ${version.graphEdges || 0} calls (${duration}ms)`
      );
    } catch (error) {
      console.error(`❌ Error rebuilding graph:`, error);
    } finally {
      this.isProcessing = false;
    }
  }

export function factorialRecursive(n: number): number {
  if (n <= 1) {
    return 1;
  }
  return n * factorialRecursive(n - 1);
}

export function isEvenMutual(n: number): boolean {
  if (n === 0) {
    return true;
  }
  return isOddMutual(Math.abs(n) - 1);
}

export function isOddMutual(n: number): boolean {
  if (n === 0) {
    return false;
  }
  return isEvenMutual(Math.abs(n) - 1);
}

export function cycleA(value: number): number {
  return cycleB(value + 1);
}

export function cycleB(value: number): number {
  return cycleC(value * 2);
}

export function cycleC(value: number): number {
  return cycleD(value - 3);
}

export function cycleD(value: number): number {
  // Close the loop back to A once, then stop for deterministic output.
  if (value <= 10) {
    return cycleA(value + 4);
  }
  return value;
}

export function runCallCycleExamples(seed: number): {
  recursive: number;
  mutual: { even: boolean; odd: boolean };
  cycle: number;
} {
  return {
    recursive: factorialRecursive(Math.max(0, seed % 8)),
    mutual: {
      even: isEvenMutual(seed),
      odd: isOddMutual(seed),
    },
    cycle: cycleA(seed),
  };
}

static async parseSourceFiles(fileContents: Map<string, string>): Promise<CodeGraph> {
    const functions = new Map<string, CodeFunction>();
    const calls = new Map<string, Set<string>>();

    // Extract function definitions from files
    this.extractFunctionDefinitions(fileContents, functions, calls);

    // Extract function calls
    this.extractFunctionCalls(fileContents, functions, calls);

    return { functions, calls };
  }

private static extractFunctionDefinitions(fileContents: Map<string, string>, functions: Map<string, CodeFunction>, calls: Map<string, Set<string>>): void {
    for (const [filePath, content] of fileContents) {
      this.processFunctionDeclarations(filePath, content, functions, calls);
    }
  }

private static processFunctionDeclarations(filePath: string, content: string, functions: Map<string, CodeFunction>, calls: Map<string, Set<string>>): void {
    const functionMatches = content.matchAll(/(?:(?:private|public|static|async)\s+)*(?:function\s+(\w+)|(\w+)\s*\([^)]*\)\s*(?::|=))/g);

    for (const match of functionMatches) {
      const functionName = match[1] || match[2];
      if (functionName && !this.isKeyword(functionName)) {
        const lineNumber = this.calculateLineNumber(content, match.index!);
        const uniqueName = `${functionName}@${filePath}`;
        functions.set(uniqueName, { name: functionName, filePath, lineNumber });
        calls.set(uniqueName, new Set());
      }
    }
  }

private static calculateLineNumber(content: string, index: number): number {
    return content.substring(0, index).split('\n').length;
  }

private static extractFunctionCalls(fileContents: Map<string, string>, functions: Map<string, CodeFunction>, calls: Map<string, Set<string>>): void {
    for (const [filePath, content] of fileContents) {
      this.processFunctionCalls(filePath, content, functions, calls);
    }
  }

private static processFunctionCalls(filePath: string, content: string, functions: Map<string, CodeFunction>, calls: Map<string, Set<string>>): void {
    const callMatches = content.matchAll(/(\w+)\s*\(/g);
    for (const match of callMatches) {
      const calledFunctionName = match[1];
      if (calledFunctionName && !this.isKeyword(calledFunctionName)) {
        const lineNumber = this.calculateLineNumber(content, match.index!);
        this.registerFunctionCall(filePath, lineNumber, calledFunctionName, functions, calls);
      }
    }
  }

private static registerFunctionCall(filePath: string, lineNumber: number, calledFunctionName: string, functions: Map<string, CodeFunction>, calls: Map<string, Set<string>>): void {
    const caller = this.findFunctionAtLine(filePath, lineNumber, functions);

    if (caller && functions.has(caller)) {
      const calledFunctions = this.findFunctionsByName(calledFunctionName, functions);

      for (const calledName of calledFunctions) {
        if (caller !== calledName) {
          const callSet = calls.get(caller) || new Set();
          callSet.add(calledName);
          calls.set(caller, callSet);
        }
      }
    }
  }

private static findFunctionsByName(name: string, functions: Map<string, CodeFunction>): string[] {
    return Array.from(functions.entries())
      .filter(([_, func]) => func.name === name)
      .map(([funcId]) => funcId);
  }

private static isKeyword(word: string): boolean {
    const keywords = [
      'if', 'else', 'for', 'while', 'do', 'switch', 'case', 'return', 'break', 'continue',
      'const', 'let', 'var', 'function', 'class', 'interface', 'new', 'this', 'super',
      'true', 'false', 'null', 'undefined', 'void', 'async', 'await', 'try', 'catch',
      'finally', 'throw', 'typeof', 'instanceof', 'delete', 'in', 'of', 'from', 'import',
      'export', 'default', 'as', 'extends', 'implements', 'abstract', 'static', 'public',
      'private', 'protected', 'readonly', 'set', 'get'
    ];
    return keywords.includes(word);
  }

private static findFunctionAtLine(filePath: string, lineNumber: number, functions: Map<string, CodeFunction>): string | null {
    const functionsByFile = Array.from(functions.entries()).filter(
      ([_, func]) => func.filePath === filePath && func.lineNumber <= lineNumber
    );

    if (functionsByFile.length === 0) return null;

    // Return the most recent function definition before this line
    return functionsByFile.sort((a, b) => b[1].lineNumber - a[1].lineNumber)[0][0];
  }

export function collectCodeViewerConnections(
  nodeId: string,
  graphData: GraphData | null,
  graphNodeMap: Map<string, GraphNode>,
): CodeViewerConnections {
  if (!nodeId || !graphData) {
    return {
      outgoingCalls: [],
      incomingCalls: [],
      externalCalls: [],
    };
  }

  const outgoingSeen = new Set<string>();
  const incomingSeen = new Set<string>();
  const externalSeen = new Set<string>();
  const outgoingCalls: GraphNode[] = [];
  const incomingCalls: GraphNode[] = [];
  const externalCalls: GraphNode[] = [];

  for (const edge of graphData.edges) {
    if (edge.from === nodeId) {
      const target = graphNodeMap.get(edge.to);
      if (target?.type === 'function' && !outgoingSeen.has(target.id)) {
        outgoingSeen.add(target.id);
        outgoingCalls.push(target);
      }
      if (target?.type === 'external' && !externalSeen.has(target.id)) {
        externalSeen.add(target.id);
        externalCalls.push(target);
      }
    }

    if (edge.to === nodeId) {
      const source = graphNodeMap.get(edge.from);
      if (source?.type === 'function' && !incomingSeen.has(source.id)) {
        incomingSeen.add(source.id);
        incomingCalls.push(source);
      }
    }
  }

  outgoingCalls.sort((a, b) => a.name.localeCompare(b.name));
  incomingCalls.sort((a, b) => a.name.localeCompare(b.name));
  externalCalls.sort((a, b) => a.name.localeCompare(b.name));

  return {
    outgoingCalls: outgoingCalls.slice(0, 6),
    incomingCalls: incomingCalls.slice(0, 6),
    externalCalls: externalCalls.slice(0, 6),
  };
}

export function drawCodeViewerConnectionButtons(
  ctx: CanvasRenderingContext2D,
  outgoingCalls: GraphNode[],
  incomingCalls: GraphNode[],
  externalCalls: GraphNode[],
  width: number,
  height: number,
  currentFilePath: string,
): CodeViewerButton[] {
  const buttons: CodeViewerButton[] = [];
  if (outgoingCalls.length === 0 && incomingCalls.length === 0 && externalCalls.length === 0) {
    return buttons;
  }

  const panelX = 32;
  const panelY = height - 268;
  const panelWidth = width - 64;
  const panelHeight = 236;

  ctx.fillStyle = 'rgba(18, 27, 40, 0.92)';
  ctx.fillRect(panelX, panelY, panelWidth, panelHeight);
  ctx.strokeStyle = 'rgba(110, 168, 255, 0.45)';
  ctx.lineWidth = 2;
  ctx.strokeRect(panelX, panelY, panelWidth, panelHeight);

  const columnGap = 12;
  const columnWidth = Math.floor((panelWidth - 28 - (columnGap * 2)) / 3);
  const incomingX = panelX + 14;
  const outgoingX = incomingX + columnWidth + columnGap;
  const externalX = outgoingX + columnWidth + columnGap;
  const buttonHeight = 28;
  const buttonGap = 6;
  const buttonWidth = columnWidth;
  let outgoingY = panelY + 40;
  let incomingY = panelY + 40;
  let externalY = panelY + 40;

  ctx.fillStyle = '#a8c7ff';
  ctx.font = '700 22px Consolas';
  ctx.fillText('Incoming Calls', incomingX, panelY + 10);
  ctx.fillText('Outgoing Calls', outgoingX, panelY + 10);
  ctx.fillText('External Calls', externalX, panelY + 10);

  ctx.font = '700 17px Consolas';
  for (const call of outgoingCalls) {
    if (outgoingY + buttonHeight > panelY + panelHeight - 8) {
      break;
    }

    ctx.fillStyle = 'rgba(32, 74, 138, 0.95)';
    ctx.fillRect(outgoingX, outgoingY, buttonWidth, buttonHeight);
    ctx.strokeStyle = 'rgba(194, 223, 255, 0.95)';
    ctx.lineWidth = 2;
    ctx.strokeRect(outgoingX, outgoingY, buttonWidth, buttonHeight);

    const targetFilePath = call.file ? toProjectRelativePath(call.file) : '';
    const filePart = targetFilePath && targetFilePath !== currentFilePath
      ? `  ${targetFilePath}`
      : '';
    let label = `→ ${call.name}${filePart}`;
    while (label.length > 1 && ctx.measureText(label).width > buttonWidth - 12) {
      label = `${label.slice(0, -2)}…`;
    }

    ctx.fillStyle = '#eaf3ff';
    ctx.strokeStyle = 'rgba(0, 0, 0, 0.9)';
    ctx.lineWidth = 3;
    ctx.strokeText(label, outgoingX + 7, outgoingY + 4);
    ctx.fillText(label, outgoingX + 7, outgoingY + 4);

    buttons.push({
      x: outgoingX,
      y: outgoingY,
      width: buttonWidth,
      height: buttonHeight,
      targetNodeId: call.id,
    });

    outgoingY += buttonHeight + buttonGap;
  }

  for (const call of incomingCalls) {
    if (incomingY + buttonHeight > panelY + panelHeight - 8) {
      break;
    }

    ctx.fillStyle = 'rgba(95, 62, 150, 0.95)';
    ctx.fillRect(incomingX, incomingY, buttonWidth, buttonHeight);
    ctx.strokeStyle = 'rgba(221, 199, 255, 0.95)';
    ctx.lineWidth = 2;
    ctx.strokeRect(incomingX, incomingY, buttonWidth, buttonHeight);

    const sourceFilePath = call.file ? toProjectRelativePath(call.file) : '';
    const filePart = sourceFilePath && sourceFilePath !== currentFilePath
      ? `  ${sourceFilePath}`
      : '';
    let label = `← ${call.name}${filePart}`;
    while (label.length > 1 && ctx.measureText(label).width > buttonWidth - 12) {
      label = `${label.slice(0, -2)}…`;
    }

    ctx.fillStyle = '#f0e8ff';
    ctx.strokeStyle = 'rgba(0, 0, 0, 0.9)';
    ctx.lineWidth = 3;
    ctx.strokeText(label, incomingX + 7, incomingY + 4);
    ctx.fillText(label, incomingX + 7, incomingY + 4);

    buttons.push({
      x: incomingX,
      y: incomingY,
      width: buttonWidth,
      height: buttonHeight,
      targetNodeId: call.id,
    });

    incomingY += buttonHeight + buttonGap;
  }

  for (const call of externalCalls) {
    if (externalY + buttonHeight > panelY + panelHeight - 8) {
      break;
    }

    ctx.fillStyle = 'rgba(42, 114, 108, 0.95)';
    ctx.fillRect(externalX, externalY, buttonWidth, buttonHeight);
    ctx.strokeStyle = 'rgba(181, 243, 230, 0.95)';
    ctx.lineWidth = 2;
    ctx.strokeRect(externalX, externalY, buttonWidth, buttonHeight);

    let label = `⇢ ${call.name}`;
    while (label.length > 1 && ctx.measureText(label).width > buttonWidth - 12) {
      label = `${label.slice(0, -2)}…`;
    }

    ctx.fillStyle = '#e8fffb';
    ctx.strokeStyle = 'rgba(0, 0, 0, 0.9)';
    ctx.lineWidth = 3;
    ctx.strokeText(label, externalX + 7, externalY + 4);
    ctx.fillText(label, externalX + 7, externalY + 4);

    buttons.push({
      x: externalX,
      y: externalY,
      width: buttonWidth,
      height: buttonHeight,
      targetNodeId: call.id,
    });

    externalY += buttonHeight + buttonGap;
  }

  return buttons;
}

export function setupCounter(element: HTMLButtonElement) {
  let counter = 0;
  element.addEventListener('click', () => {
    counter = incrementCounterValue(counter);
    updateCounterDisplay(element, counter);
  });
  initializeCounter(element);
}

function updateCounterDisplay(element: HTMLButtonElement, count: number): void {
  formatCounterText(element, count);
}

function formatCounterText(element: HTMLButtonElement, count: number): void {
  element.innerHTML = `count is ${count}`;
}

function initializeCounter(element: HTMLButtonElement): void {
  updateCounterDisplay(element, 0);
}

function incrementCounterValue(current: number): number {
  return current + 1;
}

static getFileColor(
    fileName: string,
    colorCache: Map<string, BABYLON.Color3>
  ): BABYLON.Color3 {
    if (colorCache.has(fileName)) {
      return colorCache.get(fileName)!;
    }

    const color = FileColorService.generateColorFromString(fileName);
    colorCache.set(fileName, color);
    return color;
  }

private static generateColorFromString(str: string): BABYLON.Color3 {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash;
    }

    const rawHue = (Math.abs(hash) % 360) / 360;
    const hue = FileColorService.mapToNonRedHue(rawHue);
    const saturation = 0.5 + ((Math.abs(hash) >> 8) % 100) / 200;
    const brightness = 0.6 + ((Math.abs(hash) >> 16) % 100) / 250;

    const rgb = FileColorService.hsbToRgb(hue, saturation, brightness);
    return new BABYLON.Color3(rgb.r, rgb.g, rgb.b);
  }

private static mapToNonRedHue(rawHue: number): number {
    // Restrict palette to non-red hue bands:
    // cyan/blue (0.48-0.72) and green/olive (0.23-0.42).
    // This keeps generated file colors away from red/pink tones.
    const normalized = ((rawHue % 1) + 1) % 1;
    if (normalized < 0.6) {
      return 0.48 + (normalized / 0.6) * 0.24;
    }
    return 0.23 + ((normalized - 0.6) / 0.4) * 0.19;
  }

private static hsbToRgb(h: number, s: number, b: number): { r: number; g: number; b: number } {
    const i = Math.floor(h * 6);
    const f = h * 6 - i;
    const p = b * (1 - s);
    const q = b * (1 - f * s);
    const t = b * (1 - (1 - f) * s);

    let r = 0;
    let g = 0;
    let bOut = 0;

    switch (i % 6) {
      case 0:
        r = b;
        g = t;
        bOut = p;
        break;
      case 1:
        r = q;
        g = b;
        bOut = p;
        break;
      case 2:
        r = p;
        g = b;
        bOut = t;
        break;
      case 3:
        r = p;
        g = q;
        bOut = b;
        break;
      case 4:
        r = t;
        g = p;
        bOut = b;
        break;
      case 5:
        r = b;
        g = p;
        bOut = q;
        break;
    }

    return { r, g, b: bOut };
  }

public simulate(iterations: number = 300): Map<string, Node> {
    const nodeArray = Array.from(this.nodes.values());
    const nodeCount = nodeArray.length;

    for (let iter = 0; iter < iterations; iter++) {
      let maxVelocity = 0;

      // Reset forces
      for (const node of nodeArray) {
        node.velocity = { x: 0, y: 0, z: 0 };
      }

      // Apply repulsive forces between all node pairs
      for (let i = 0; i < nodeCount; i++) {
        for (let j = i + 1; j < nodeCount; j++) {
          this.applyRepulsiveForce(nodeArray[i], nodeArray[j]);
        }
      }

      // Apply attractive forces along edges
      const edgesToProcess = this.edgeFilter ? this.edges.filter(this.edgeFilter) : this.edges;
      for (const edge of edgesToProcess) {
        const sourceNode = this.nodes.get(edge.source);
        const targetNode = this.nodes.get(edge.target);
        if (sourceNode && targetNode) {
          this.applyAttractiveForce(sourceNode, targetNode);
        }
      }

      // Update positions and apply damping
      for (const node of nodeArray) {
        node.velocity.x *= this.DAMPING;
        node.velocity.y *= this.DAMPING;
        node.velocity.z *= this.DAMPING;

        node.position.x += node.velocity.x;
        node.position.y += node.velocity.y;
        node.position.z += node.velocity.z;

        // Constrain to bounds
        node.position.x = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, node.position.x));
        node.position.y = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, node.position.y));
        node.position.z = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, node.position.z));

        const speed = Math.sqrt(node.velocity.x ** 2 + node.velocity.y ** 2 + node.velocity.z ** 2);
        maxVelocity = Math.max(maxVelocity, speed);
      }

      this.enforceFileCrossConstraint();

      // Early exit if layout converged
      if (maxVelocity < this.EQUILIBRIUM_THRESHOLD) {
        break;
      }
    }

    return this.nodes;
  }

private applyRepulsiveForce(nodeA: Node, nodeB: Node): void {
    const dx = nodeB.position.x - nodeA.position.x;
    const dy = nodeB.position.y - nodeA.position.y;
    const dz = nodeB.position.z - nodeA.position.z;

    const rawDistance = Math.sqrt(dx * dx + dy * dy + dz * dz);
    const combinedRadius = nodeA.radius + nodeB.radius;
    const minDistance = Math.max(this.MIN_DISTANCE, combinedRadius);
    const distance = Math.max(rawDistance, minDistance);

    // All repulsive forces use same-file strength (cross-file nodes don't repel)
    const repulsiveConstant = this.C_REPULSIVE;

    let force = (repulsiveConstant / (distance * distance)) || 0;
    if (rawDistance < combinedRadius) {
      // Extra separation when larger nodes overlap so they settle farther apart.
      const overlapRatio = (combinedRadius - rawDistance) / combinedRadius;
      force *= 1 + overlapRatio * 6;
    }

    const fx = (force * dx) / distance;
    const fy = (force * dy) / distance;
    const fz = (force * dz) / distance;

    // Apply force: push away from each other
    nodeA.velocity.x -= fx;
    nodeA.velocity.y -= fy;
    nodeA.velocity.z -= fz;

    nodeB.velocity.x += fx;
    nodeB.velocity.y += fy;
    nodeB.velocity.z += fz;
  }

private applyAttractiveForce(nodeA: Node, nodeB: Node): void {
    const dx = nodeB.position.x - nodeA.position.x;
    const dy = nodeB.position.y - nodeA.position.y;
    const dz = nodeB.position.z - nodeA.position.z;

    const distance = Math.sqrt(dx * dx + dy * dy + dz * dz) || this.MIN_DISTANCE;

    // Check if same file connection
    const isSameFile = nodeA.file && nodeB.file && nodeA.file === nodeB.file;

    // Use strongest attraction for same-file connected nodes (6x stronger)
    const attractionConstant = isSameFile ? this.C_ATTRACTIVE_SAME_FILE : this.C_ATTRACTIVE;

    // Size-aware spring: target edge length scales with node radii so larger nodes keep clearance.
    const restLength = Math.max(this.MIN_DISTANCE, (nodeA.radius + nodeB.radius) * 1.15);
    const force = attractionConstant * (distance - restLength);

    const fx = (force * dx) / distance;
    const fy = (force * dy) / distance;
    const fz = (force * dz) / distance;

    // Apply force: pull toward each other
    nodeA.velocity.x += fx;
    nodeA.velocity.y += fy;
    nodeA.velocity.z += fz;

    nodeB.velocity.x -= fx;
    nodeB.velocity.y -= fy;
    nodeB.velocity.z -= fz;
  }

public updateFrame(): boolean {
    const nodeArray = Array.from(this.nodes.values());
    const nodeCount = nodeArray.length;
    let maxVelocity = 0;

    // Reset forces for this frame
    for (const node of nodeArray) {
      node.velocity = { x: 0, y: 0, z: 0 };
    }

    // Apply repulsive forces between all node pairs
    for (let i = 0; i < nodeCount; i++) {
      for (let j = i + 1; j < nodeCount; j++) {
        this.applyRepulsiveForce(nodeArray[i], nodeArray[j]);
      }
    }

    // Apply attractive forces along edges (filtered if edge filter is specified)
    const edgesToProcess = this.edgeFilter ? this.edges.filter(this.edgeFilter) : this.edges;
    for (const edge of edgesToProcess) {
      const sourceNode = this.nodes.get(edge.source);
      const targetNode = this.nodes.get(edge.target);
      if (sourceNode && targetNode) {
        this.applyAttractiveForce(sourceNode, targetNode);
      }
    }

    // Update positions and apply damping
    for (const node of nodeArray) {
      // Apply damping to velocity
      node.velocity.x *= this.DAMPING;
      node.velocity.y *= this.DAMPING;
      node.velocity.z *= this.DAMPING;

      // Update position based on velocity
      node.position.x += node.velocity.x;
      node.position.y += node.velocity.y;
      node.position.z += node.velocity.z;

      // Constrain to bounds
      node.position.x = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, node.position.x));
      node.position.y = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, node.position.y));
      node.position.z = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, node.position.z));

      // Track max velocity for convergence check
      const speed = Math.sqrt(node.velocity.x ** 2 + node.velocity.y ** 2 + node.velocity.z ** 2);
      maxVelocity = Math.max(maxVelocity, speed);
    }

    // Enforce stronger minimum distance constraint between nodes from different files
    this.enforceFileCrossConstraint();

    // Return true if still converging, false if settled
    return maxVelocity >= this.EQUILIBRIUM_THRESHOLD;
  }

private enforceFileCrossConstraint(): void {
    const nodeArray = Array.from(this.nodes.values());
    const nodeCount = nodeArray.length;
    const pushForce = this.C_REPULSIVE_CROSS_FILE * 3;  // Strong push for file boundaries

    for (let i = 0; i < nodeCount; i++) {
      for (let j = i + 1; j < nodeCount; j++) {
        const nodeA = nodeArray[i];
        const nodeB = nodeArray[j];

        // Only enforce constraint for nodes from different files
        if (!nodeA.file || !nodeB.file || nodeA.file === nodeB.file) {
          continue;  // Skip if same file or no file info
        }

        const dx = nodeB.position.x - nodeA.position.x;
        const dy = nodeB.position.y - nodeA.position.y;
        const dz = nodeB.position.z - nodeA.position.z;

        const distance = Math.sqrt(dx * dx + dy * dy + dz * dz) || this.MIN_DISTANCE;

        const sizeAwareSeparation = Math.max(this.MIN_CROSS_FILE_SEPARATION, (nodeA.radius + nodeB.radius) * 2.0);

        // If cross-file nodes are closer than minimum distance, push them apart strongly
        if (distance < sizeAwareSeparation) {
          const direction = distance > 0 
            ? { x: dx / distance, y: dy / distance, z: dz / distance }
            : { x: Math.random() - 0.5, y: Math.random() - 0.5, z: Math.random() - 0.5 };

          // Calculate how much to push (stronger for cross-file)
          const pushAmount = (sizeAwareSeparation - distance) * pushForce;

          // Push nodes apart
          nodeA.position.x -= direction.x * pushAmount;
          nodeA.position.y -= direction.y * pushAmount;
          nodeA.position.z -= direction.z * pushAmount;

          nodeB.position.x += direction.x * pushAmount;
          nodeB.position.y += direction.y * pushAmount;
          nodeB.position.z += direction.z * pushAmount;

          // Re-constrain to bounds after pushing
          nodeA.position.x = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, nodeA.position.x));
          nodeA.position.y = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, nodeA.position.y));
          nodeA.position.z = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, nodeA.position.z));

          nodeB.position.x = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, nodeB.position.x));
          nodeB.position.y = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, nodeB.position.y));
          nodeB.position.z = Math.max(-this.SPACE_SIZE, Math.min(this.SPACE_SIZE, nodeB.position.z));
        }
      }
    }
  }

public getNodes(): Map<string, Node> {
    return this.nodes;
  }

ensureFunctionEditorScreen(): void {
    if (this.state.functionEditorScreen && this.state.functionEditorTexture && this.state.functionEditorMaterial) {
      return;
    }

    const screen = BABYLON.MeshBuilder.CreatePlane(
      'functionEditorScreen',
      { width: 1, height: 1 },
      this.scene,
    );
    screen.isPickable = true;
    screen.alwaysSelectAsActiveMesh = true;
    screen.setEnabled(false);

    const texture = new BABYLON.DynamicTexture(
      'functionEditorTexture',
      { width: EDITOR_TEXTURE_WIDTH, height: EDITOR_TEXTURE_HEIGHT },
      this.scene,
      true,
    );
    texture.hasAlpha = true;
    texture.uScale = -1;
    texture.uOffset = 1;

    const material = new BABYLON.StandardMaterial('functionEditorMaterial', this.scene);
    material.diffuseTexture = texture;
    material.opacityTexture = texture;
    material.emissiveTexture = texture;
    material.emissiveColor = new BABYLON.Color3(1, 1, 1);
    material.disableLighting = true;
    material.disableDepthWrite = true;
    material.zOffset = -6;
    material.backFaceCulling = false;
    screen.material = material;
    screen.renderingGroupId = 3;
    screen.alphaIndex = 1000;

    this.state.functionEditorScreen = screen;
    this.state.functionEditorTexture = texture;
    this.state.functionEditorMaterial = material;
  }

showFunctionEditor(node: GraphNode): void {
    if (!node.code || !node.id) {
      this.hideFunctionEditor();
      return;
    }

    const hostMesh = this.state.nodeMeshMap.get(node.id);
    if (!hostMesh) {
      this.hideFunctionEditor();
      return;
    }

    this.ensureFunctionEditorScreen();
    if (!this.state.functionEditorScreen || !this.state.functionEditorTexture) {
      return;
    }

    const meshAny = hostMesh as any;
    const boxSize = typeof meshAny.boxSize === 'number'
      ? meshAny.boxSize
      : Math.max(1.0, (hostMesh.getBoundingInfo()?.boundingSphere?.radiusWorld ?? 1) * 1.15);

    this.drawFunctionEditorTexture(node);
    this.attachEditorScreenToVisibleFace(hostMesh, boxSize, node.id);
    this.state.functionEditorScreen.setEnabled(true);
    this.state.editorVisibleForNodeId = node.id;
    this.state.editorCurrentNodeId = node.id;

    console.log('🖥️ Editor shown', {
      nodeId: node.id,
      name: node.name,
      file: node.file,
      line: node.line,
      selectedFunctionId: this.state.currentFunctionId,
      selectedFaceNormal: this.state.currentFaceNormal ? this.formatDebugVector(this.state.currentFaceNormal) : null,
      codeLength: node.code.length,
    });
  }

hideFunctionEditor(): void {
    const previousNodeId = this.state.editorVisibleForNodeId;
    this.state.editorVisibleForNodeId = null;
    this.state.editorCurrentNodeId = null;
    this.state.editorCallButtons = [];
    this.state.editorScrollButtons = [];
    this.state.editorCurrentCodeLineCount = 0;
    this.state.editorCurrentCodeMaxLines = 0;
    this.state.lastEditorAttachmentSignature = null;
    if (this.state.functionEditorScreen) {
      this.state.functionEditorScreen.parent = null;
      this.state.functionEditorScreen.setEnabled(false);
    }
    if (previousNodeId) {
      console.log('🖥️ Editor hidden', { nodeId: previousNodeId });
    }
  }

handleEditorScreenClick(uv: BABYLON.Vector2): boolean {
    if (!this.state.editorCurrentNodeId) {
      return false;
    }

    const texX = (1 - uv.x) * EDITOR_TEXTURE_WIDTH;
    const texY = (1 - uv.y) * EDITOR_TEXTURE_HEIGHT;

    // Check close button first (top-right corner)
    const closeButtonSize = 60;
    const closeButtonX = EDITOR_TEXTURE_WIDTH - closeButtonSize - 12;
    const closeButtonY = 12;
    if (texX >= closeButtonX && texX <= closeButtonX + closeButtonSize
        && texY >= closeButtonY && texY <= closeButtonY + closeButtonSize) {
      this.hideFunctionEditor();
      return true;
    }

    for (const btn of this.state.editorScrollButtons) {
      const inside = texX >= btn.x && texX <= (btn.x + btn.width)
        && texY >= btn.y && texY <= (btn.y + btn.height);
      if (!inside) continue;
      return this.applyEditorScrollAction(btn.action);
    }

    for (const btn of this.state.editorCallButtons) {
      const inside = texX >= btn.x && texX <= (btn.x + btn.width)
        && texY >= btn.y && texY <= (btn.y + btn.height);
      if (!inside) continue;

      const targetMesh = this.state.nodeMeshMap.get(btn.targetNodeId);
      if (!targetMesh) return false;

      const toViewer = this.getViewerWorldPosition().subtract(targetMesh.getAbsolutePosition());
      let faceNormal = new BABYLON.Vector3(0, 0, 1);
      const absX = Math.abs(toViewer.x);
      const absZ = Math.abs(toViewer.z);
      if (absX >= absZ) {
        faceNormal = new BABYLON.Vector3(toViewer.x >= 0 ? 1 : -1, 0, 0);
      } else {
        faceNormal = new BABYLON.Vector3(0, 0, toViewer.z >= 0 ? 1 : -1);
      }

      this.onNavigateToMesh(targetMesh, faceNormal);
      return true;
    }

    return this.focusCurrentEditorFaceCloseUp();
  }

updateFunctionEditorProximity(): void {
    const nearbyNode = this.findNearbyFunctionForEditor();
    if (!nearbyNode) {
      if (this.state.editorVisibleForNodeId !== null) {
        this.hideFunctionEditor();
      }
      return;
    }

    if (this.state.editorVisibleForNodeId === nearbyNode.id) {
      const hostMesh = this.state.nodeMeshMap.get(nearbyNode.id);
      if (hostMesh && this.state.functionEditorScreen) {
        const meshAny = hostMesh as any;
        const boxSize = typeof meshAny.boxSize === 'number'
          ? meshAny.boxSize
          : Math.max(1.0, (hostMesh.getBoundingInfo()?.boundingSphere?.radiusWorld ?? 1) * 1.15);
        this.attachEditorScreenToVisibleFace(hostMesh, boxSize, nearbyNode.id);
      }
      return;
    }

    if (this.state.editorVisibleForNodeId && this.state.editorVisibleForNodeId !== nearbyNode.id) {
      this.hideFunctionEditor();
    }

    this.showFunctionEditor(nearbyNode);
  }

attachEditorScreenToVisibleFace(hostMesh: BABYLON.Mesh, boxSize: number, nodeId: string): void {
    if (!this.state.functionEditorScreen) return;

    const screen = this.state.functionEditorScreen;
    const faceNormal = this.getPreferredEditorFaceNormal(nodeId, hostMesh);

    const absX = Math.abs(faceNormal.x);
    const absY = Math.abs(faceNormal.y);
    const absZ = Math.abs(faceNormal.z);
    const half = boxSize * 0.5;
    const offset = Math.max(0.14, boxSize * 0.045);

    let position = new BABYLON.Vector3(0, 0, half + offset);
    let rotation = BABYLON.Vector3.Zero();

    if (absX >= absY && absX >= absZ) {
      if (faceNormal.x >= 0) {
        position = new BABYLON.Vector3(half + offset, 0, 0);
        rotation = new BABYLON.Vector3(0, Math.PI / 2, 0);
      } else {
        position = new BABYLON.Vector3(-(half + offset), 0, 0);
        rotation = new BABYLON.Vector3(0, -Math.PI / 2, 0);
      }
    } else if (absY >= absX && absY >= absZ) {
      if (faceNormal.y >= 0) {
        position = new BABYLON.Vector3(0, half + offset, 0);
        rotation = new BABYLON.Vector3(-Math.PI / 2, 0, 0);
      } else {
        position = new BABYLON.Vector3(0, -(half + offset), 0);
        rotation = new BABYLON.Vector3(Math.PI / 2, 0, 0);
      }
    } else if (faceNormal.z < 0) {
      position = new BABYLON.Vector3(0, 0, -(half + offset));
      rotation = new BABYLON.Vector3(0, Math.PI, 0);
    }

    screen.parent = hostMesh;
    screen.position = position;
    screen.rotationQuaternion = null;
    screen.rotation = rotation;
    screen.scaling = new BABYLON.Vector3(
      boxSize * EDITOR_WORLD_WIDTH_SCALE,
      boxSize * EDITOR_WORLD_HEIGHT_SCALE,
      1,
    );
    (screen as any).editorHostNodeId = nodeId;

    const attachmentSignature = [
      nodeId,
      position.x.toFixed(3),
      position.y.toFixed(3),
      position.z.toFixed(3),
      rotation.x.toFixed(3),
      rotation.y.toFixed(3),
      rotation.z.toFixed(3),
    ].join('|');
    if (attachmentSignature !== this.state.lastEditorAttachmentSignature) {
      this.state.lastEditorAttachmentSignature = attachmentSignature;
      console.log('🖥️ Editor screen attached', {
        nodeId,
        faceNormal: this.formatDebugVector(faceNormal),
        localPosition: this.formatDebugVector(position),
        localRotation: this.formatDebugVector(rotation),
        boxSize: Number(boxSize.toFixed(3)),
      });
    }
  }

private drawFunctionEditorTexture(node: GraphNode): void {
    if (!this.state.functionEditorTexture) return;

    const width = EDITOR_TEXTURE_WIDTH;
    const height = EDITOR_TEXTURE_HEIGHT;
    const ctx = this.state.functionEditorTexture.getContext() as CanvasRenderingContext2D;
    ctx.clearRect(0, 0, width, height);

    ctx.fillStyle = 'rgba(5, 9, 16, 0.98)';
    ctx.fillRect(0, 0, width, height);

    ctx.strokeStyle = 'rgba(188, 228, 255, 0.38)';
    ctx.lineWidth = 6;
    ctx.strokeRect(8, 8, width - 16, height - 16);

    ctx.fillStyle = 'rgba(26, 38, 57, 0.95)';
    ctx.fillRect(16, 16, width - 32, 88);

    // Draw close button (X) in top-right corner
    const closeButtonSize = 60;
    const closeButtonX = width - closeButtonSize - 12;
    const closeButtonY = 12;
    ctx.fillStyle = 'rgba(220, 50, 50, 0.85)';
    ctx.fillRect(closeButtonX, closeButtonY, closeButtonSize, closeButtonSize);
    ctx.strokeStyle = 'rgba(255, 100, 100, 0.95)';
    ctx.lineWidth = 3;
    ctx.strokeRect(closeButtonX, closeButtonY, closeButtonSize, closeButtonSize);
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.9)';
    ctx.lineWidth = 4;
    ctx.beginPath();
    ctx.moveTo(closeButtonX + 14, closeButtonY + 14);
    ctx.lineTo(closeButtonX + closeButtonSize - 14, closeButtonY + closeButtonSize - 14);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(closeButtonX + closeButtonSize - 14, closeButtonY + 14);
    ctx.lineTo(closeButtonX + 14, closeButtonY + closeButtonSize - 14);
    ctx.stroke();

    ctx.fillStyle = '#f6f9ff';
    ctx.font = '700 36px Consolas';
    ctx.textAlign = 'left';
    ctx.textBaseline = 'top';
    ctx.fillText(node.name, 40, 34);

    const metaParts = [node.file ? toProjectRelativePath(node.file) : undefined, node.line ? `line ${node.line}` : undefined]
      .filter((part): part is string => Boolean(part));
    ctx.fillStyle = '#b3cae8';
    ctx.font = '25px Consolas';
    ctx.fillText(metaParts.join('  •  '), 40, 72);

    ctx.fillStyle = 'rgba(10, 16, 26, 0.98)';
    const codeAreaPanelX = 26;
    const codeAreaPanelY = 126;
    const codeAreaPanelWidth = width - 52;
    const codeAreaPanelHeight = height - 140;
    ctx.fillRect(codeAreaPanelX, codeAreaPanelY, codeAreaPanelWidth, codeAreaPanelHeight);
    ctx.strokeStyle = 'rgba(122, 168, 220, 0.28)';
    ctx.lineWidth = 2;
    ctx.strokeRect(codeAreaPanelX, codeAreaPanelY, codeAreaPanelWidth, codeAreaPanelHeight);

    ctx.font = '24px Consolas';
    const codeAreaX = 40;
    const codeAreaY = 138;
    const codeAreaWidth = width - 140;
    const lineHeight = 31;
    const viewerConnections = collectCodeViewerConnections(node.id || '', this.state.currentGraphData, this.state.graphNodeMap);
    const { outgoingCalls, incomingCalls, externalCalls } = viewerConnections;
    const currentFilePath = node.file ? toProjectRelativePath(node.file) : '';
    const hasCallButtons = outgoingCalls.length > 0 || incomingCalls.length > 0 || externalCalls.length > 0;
    const reserveFooterHeight = hasCallButtons ? 280 : 30;
    const maxLines = Math.floor((height - codeAreaY - reserveFooterHeight) / lineHeight);
    const requestedStartLine = this.state.editorCodeScrollByNodeId.get(node.id || '') ?? 0;

    const codeRender = this.drawHighlightedCode(
      ctx, node.code || '', codeAreaX, codeAreaY, codeAreaWidth, lineHeight, maxLines, requestedStartLine,
    );
    this.state.editorCodeScrollByNodeId.set(node.id || '', codeRender.appliedStartLine);
    this.state.editorCurrentCodeLineCount = codeRender.totalLines;
    this.state.editorCurrentCodeMaxLines = Math.max(1, maxLines);
    this.drawCodeScrollControls(ctx, codeAreaX, codeAreaY, codeAreaWidth, lineHeight, maxLines, codeRender);
    this.state.editorCallButtons = drawCodeViewerConnectionButtons(
      ctx, outgoingCalls, incomingCalls, externalCalls, width, height, currentFilePath,
    );

    this.state.functionEditorTexture.update();
  }

private focusCurrentEditorFaceCloseUp(): boolean {
    if (!this.state.editorCurrentNodeId) return false;

    const mesh = this.state.nodeMeshMap.get(this.state.editorCurrentNodeId);
    if (!mesh) return false;

    let faceNormal = this.state.currentFaceNormal?.clone() || new BABYLON.Vector3(0, 0, 1);
    faceNormal = this.coerceFaceNormalToSide(faceNormal, faceNormal);

    this.state.currentFunctionId = this.state.editorCurrentNodeId;
    this.state.currentFaceNormal = faceNormal.clone();

    // NavigationController.flyToWorldPosition wired via onNavigateToMesh:
    // pass a neutral face so the caller routes via the face-normal path.
    this.onNavigateToMesh(mesh, faceNormal);
    return true;
  }

private findNearbyFunctionForEditor(): GraphNode | null {
    const viewerWorldPos = this.getViewerWorldPosition();

    if (this.state.currentFunctionId) {
      const selectedNode = this.state.graphNodeMap.get(this.state.currentFunctionId);
      const selectedMesh = this.state.nodeMeshMap.get(this.state.currentFunctionId);
      if (selectedNode && selectedMesh && selectedNode.type === 'function' && selectedNode.code
        && selectedMesh.isEnabled() && selectedMesh.isVisible) {
        return selectedNode;
      }
    }

    let closestNode: GraphNode | null = null;
    let closestDistance = Number.POSITIVE_INFINITY;

    for (const [nodeId, mesh] of this.state.nodeMeshMap.entries()) {
      const node = this.state.graphNodeMap.get(nodeId);
      if (!node || node.type !== 'function' || !node.code || !mesh.isEnabled() || !mesh.isVisible) continue;

      const radius = mesh.getBoundingInfo()?.boundingSphere?.radiusWorld ?? 0;
      const activationDistance = Math.max(12, radius + 6);
      const distance = BABYLON.Vector3.Distance(viewerWorldPos, mesh.getAbsolutePosition());
      if (distance > activationDistance || distance >= closestDistance) continue;

      closestDistance = distance;
      closestNode = node;
    }

    return closestNode;
  }

private getPreferredEditorFaceNormal(nodeId: string, hostMesh: BABYLON.Mesh): BABYLON.Vector3 {
    if (this.state.currentFunctionId === nodeId && this.state.currentFaceNormal) {
      return this.state.currentFaceNormal.clone();
    }

    const viewerWorldPos = this.getViewerWorldPosition();
    let fallback = viewerWorldPos.subtract(hostMesh.getAbsolutePosition());
    if (!Number.isFinite(fallback.length()) || fallback.lengthSquared() < 0.000001) {
      fallback = new BABYLON.Vector3(0, 0, 1);
    }
    return fallback;
  }

private flattenPrismTokens(
    tokens: Array<string | Prism.Token>,
    parentType = '',
  ): Array<{ type: string; text: string }> {
    const result: Array<{ type: string; text: string }> = [];
    for (const token of tokens) {
      if (typeof token === 'string') {
        if (token.length > 0) result.push({ type: parentType, text: token });
      } else {
        const content = token.content;
        if (typeof content === 'string') {
          result.push({ type: token.type, text: content });
        } else if (Array.isArray(content)) {
          result.push(...this.flattenPrismTokens(content as Array<string | Prism.Token>, token.type));
        }
      }
    }
    return result;
  }

private drawHighlightedCode(
    ctx: CanvasRenderingContext2D,
    code: string,
    x: number,
    startY: number,
    maxWidth: number,
    lineHeight: number,
    maxLines: number,
    startLine: number,
  ): { totalLines: number; appliedStartLine: number } {
    const grammar = Prism.languages['typescript'] ?? Prism.languages['javascript'] ?? Prism.languages.clike;
    const rawTokens = Prism.tokenize(code, grammar) as Array<string | Prism.Token>;
    const flat = this.flattenPrismTokens(rawTokens);

    const sourceLines: Array<Array<{ type: string; text: string }>> = [[]];
    for (const seg of flat) {
      const parts = seg.text.split('\n');
      for (let i = 0; i < parts.length; i++) {
        if (parts[i].length > 0) {
          sourceLines[sourceLines.length - 1].push({ type: seg.type, text: parts[i] });
        }
        if (i < parts.length - 1) {
          sourceLines.push([]);
        }
      }
    }

    const safeMaxLines = Math.max(1, maxLines);
    const maxStart = Math.max(0, sourceLines.length - safeMaxLines);
    const appliedStartLine = Math.max(0, Math.min(startLine, maxStart));

    let drawY = startY;
    let rendered = 0;
    for (let li = appliedStartLine; li < sourceLines.length && rendered < safeMaxLines; li++) {
      this.drawHighlightedLine(ctx, sourceLines[li], x, drawY, maxWidth);
      drawY += lineHeight;
      rendered++;
    }

    return { totalLines: sourceLines.length, appliedStartLine };
  }

private drawCodeScrollControls(
    ctx: CanvasRenderingContext2D,
    codeAreaX: number,
    codeAreaY: number,
    codeAreaWidth: number,
    lineHeight: number,
    maxLines: number,
    codeRender: { totalLines: number; appliedStartLine: number },
  ): void {
    this.state.editorScrollButtons = [];
    if (codeRender.totalLines <= maxLines) return;

    const buttonWidth = 38;
    const buttonHeight = 28;
    const scrollX = codeAreaX + codeAreaWidth + 12;
    const viewportHeight = Math.max(1, maxLines * lineHeight);
    const upY = codeAreaY + 4;
    const downY = codeAreaY + viewportHeight - buttonHeight - 4;

    const drawButton = (x: number, y: number, label: string): void => {
      ctx.fillStyle = 'rgba(56, 84, 128, 0.90)';
      ctx.fillRect(x, y, buttonWidth, buttonHeight);
      ctx.strokeStyle = 'rgba(182, 212, 255, 0.85)';
      ctx.lineWidth = 1.5;
      ctx.strokeRect(x, y, buttonWidth, buttonHeight);
      ctx.fillStyle = '#eef5ff';
      ctx.font = '700 20px Consolas';
      ctx.fillText(label, x + 11, y + 3);
    };

    drawButton(scrollX, upY, '↑');
    drawButton(scrollX, downY, '↓');

    this.state.editorScrollButtons.push({ x: scrollX, y: upY, width: buttonWidth, height: buttonHeight, action: 'up' });
    this.state.editorScrollButtons.push({ x: scrollX, y: downY, width: buttonWidth, height: buttonHeight, action: 'down' });

    const firstVisible = codeRender.appliedStartLine + 1;
    const lastVisible = Math.min(codeRender.totalLines, codeRender.appliedStartLine + maxLines);
    ctx.fillStyle = '#9fc1e8';
    ctx.font = '14px Consolas';
    const indicator = `${firstVisible}-${lastVisible}/${codeRender.totalLines}`;
    ctx.fillText(indicator, scrollX - 12, upY + buttonHeight + 8);
  }

private applyEditorScrollAction(action: 'up' | 'down'): boolean {
    if (!this.state.editorCurrentNodeId) return false;

    const node = this.state.graphNodeMap.get(this.state.editorCurrentNodeId);
    if (!node || node.type !== 'function' || !node.code) return false;

    const current = this.state.editorCodeScrollByNodeId.get(node.id) ?? 0;
    const maxStart = Math.max(0, this.state.editorCurrentCodeLineCount - this.state.editorCurrentCodeMaxLines);
    const step = Math.max(1, Math.floor(this.state.editorCurrentCodeMaxLines * 0.35));
    const next = action === 'up'
      ? Math.max(0, current - step)
      : Math.min(maxStart, current + step);

    if (next === current) return true;

    this.state.editorCodeScrollByNodeId.set(node.id, next);
    this.drawFunctionEditorTexture(node);
    return true;
  }

private drawHighlightedLine(
    ctx: CanvasRenderingContext2D,
    segs: Array<{ type: string; text: string }>,
    x: number,
    y: number,
    maxWidth: number,
  ): void {
    let curX = x;
    const ellipsisWidth = ctx.measureText('...').width;
    for (const seg of segs) {
      ctx.fillStyle = PRISM_TOKEN_COLORS[seg.type] ?? PRISM_DEFAULT_COLOR;
      ctx.strokeStyle = 'rgba(0, 0, 0, 0.85)';
      ctx.lineWidth = 2;
      ctx.lineJoin = 'round';
      const segWidth = ctx.measureText(seg.text).width;
      if (curX + segWidth <= x + maxWidth) {
        ctx.strokeText(seg.text, curX, y);
        ctx.fillText(seg.text, curX, y);
        curX += segWidth;
      } else {
        let truncated = seg.text;
        while (truncated.length > 0 && curX + ctx.measureText(truncated).width + ellipsisWidth > x + maxWidth) {
          truncated = truncated.slice(0, -1);
        }
        ctx.strokeText(truncated + '...', curX, y);
        ctx.fillText(truncated + '...', curX, y);
        return;
      }
    }
  }

dispose(): void {
    this.state.functionEditorScreen?.dispose(false, true);
    this.state.functionEditorMaterial?.dispose();
    this.state.functionEditorTexture?.dispose();
    this.state.functionEditorScreen = null;
    this.state.functionEditorMaterial = null;
    this.state.functionEditorTexture = null;
  }

async checkForUpdates(): Promise<boolean> {
    try {
      const baseUrl = import.meta.env.BASE_URL;
      const versionUrl = `${baseUrl}version.json`;

      const response = await fetch(versionUrl);
      if (!response.ok) return false;

      const versionData = await response.json();
      const currentVersion = versionData.buildTime;

      if (currentVersion !== this.lastSeenVersion) {
        this.lastSeenVersion = currentVersion;
        return true;  // Version changed, should reload graph
      }

      return false;  // No update needed
    } catch (error) {
      console.warn('Error checking version:', error);
      return false;
    }
  }

async loadGraph(): Promise<GraphData | null> {
    try {
      // Use BASE_URL which respects Vite's base configuration
      // In dev: /unitcircle/ 
      // In prod: /unitcircle/
      const baseUrl = import.meta.env.BASE_URL;
      const url = `${baseUrl}graph.json`;

      const response = await fetch(url);

      if (response.ok) {
        const data = await response.json();
        this.cache = data;
        this.lastLoadTime = Date.now();
        const graphVersion = data.lastUpdated || '';
        // Prime version tracking on the initial load so the first poll doesn't
        // immediately treat the current graph as a new update. This is safe as
        // long as graph.lastUpdated and version.json.buildTime are kept in sync.
        if (!this.lastSeenVersion && graphVersion) {
          this.lastSeenVersion = graphVersion;
        }
        if (graphVersion !== this.lastLoggedGraphVersion) {
          console.log(`✓ Loaded graph with ${data.nodes?.length || 0} functions and ${data.edges?.length || 0} calls`);
          this.lastLoggedGraphVersion = graphVersion;
        }
        return data;
      }

      console.warn(`Failed to load graph: ${response.status} ${response.statusText}`);
      // If fetch fails, try returning cached version
      if (this.cache) {
        console.warn('Using cached graph data');
        return this.cache;
      }
      return null;
    } catch (error) {
      console.error('Error loading graph:', error);
      // Return cached version if available
      if (this.cache) {
        console.warn('Using cached graph data due to error');
        return this.cache;
      }
      return null;
    }
  }

getCachedGraph(): GraphData | null {
    return this.cache;
  }

shouldPoll(): boolean {
    const timeSinceLastLoad = Date.now() - this.lastLoadTime;
    return timeSinceLastLoad >= this.pollIntervalMs;
  }

setPollInterval(intervalMs: number): void {
    this.pollIntervalMs = intervalMs;
  }

public clearScene(): void {
    // Dispose all node meshes
    for (const mesh of this.nodeMeshMap.values()) {
      mesh.dispose(false, true);
    }
    this.nodeMeshMap.clear();
    this.meshFactory.clearNodeReferences();

    // Dispose all edge meshes
    this.meshFactory.clearEdges();

    // Dispose all file box outlines
    for (const mesh of this.fileBoxMeshes.values()) {
      mesh.dispose(false, true);
    }
    this.fileBoxMeshes.clear();

    // Dispose all directory box outlines
    for (const mesh of this.directoryBoxMeshes.values()) {
      mesh.dispose(false, true);
    }
    this.directoryBoxMeshes.clear();

    // Dispose labels
    for (const mesh of this.fileBoxLabels.values()) {
      mesh.dispose(false, true);
    }
    this.fileBoxLabels.clear();

    for (const mesh of this.directoryBoxLabels.values()) {
      mesh.dispose(false, true);
    }
    this.directoryBoxLabels.clear();

    this.lastFileBoxScales.clear();
    this.lastDirectoryBoxScales.clear();
  }

public renderFileBoxes(fileBoxDimensions: Map<string, BABYLON.Vector3>): void {
    for (const [file, dims] of fileBoxDimensions) {
      if (this.fileBoxMeshes.has(file)) continue; // Already exists

      const box = BABYLON.MeshBuilder.CreateBox(
        `filebox_${file}`,
        { size: 1 },
        this.scene,
      );
      box.parent = this.sceneRoot;
      box.isPickable = true;
      box.scaling = dims.clone();

      // Wireframe material
      const mat = new BABYLON.StandardMaterial(`filebox_mat_${file}`, this.scene);
      mat.wireframe = true;
      mat.alpha = 0.18;
      mat.transparencyMode = BABYLON.Material.MATERIAL_ALPHABLEND;
      mat.needDepthPrePass = true;
      mat.disableDepthWrite = true;
      mat.emissiveColor = new BABYLON.Color3(0.4, 0.6, 0.8);
      box.material = mat;

      this.fileBoxMeshes.set(file, box);
      this.lastFileBoxScales.set(file, dims.clone());
    }
  }

public renderDirectoryBoxes(directoryBoxDimensions: Map<string, { position: BABYLON.Vector3; scaling: BABYLON.Vector3 }>): void {
    for (const [dirPath, { position, scaling }] of directoryBoxDimensions) {
      if (this.directoryBoxMeshes.has(dirPath)) {
        const existing = this.directoryBoxMeshes.get(dirPath)!;
        existing.position.copyFrom(position);
        existing.scaling.copyFrom(scaling);
        continue;
      }

      const box = BABYLON.MeshBuilder.CreateBox(
        `dirbox_${dirPath}`,
        { size: 1 },
        this.scene,
      );
      box.parent = this.sceneRoot;
      box.position.copyFrom(position);
      box.scaling.copyFrom(scaling);
      box.isPickable = false;

      const mat = new BABYLON.StandardMaterial(`dirbox_mat_${dirPath}`, this.scene);
      mat.wireframe = true;
      mat.alpha = 0.08;
      mat.emissiveColor = new BABYLON.Color3(0.3, 0.5, 0.7);
      box.material = mat;

      this.directoryBoxMeshes.set(dirPath, box);
    }
  }

public renderNodes(
    nodes: GraphNode[],
    nodePositions: Map<string, BABYLON.Vector3>,
    fileColorMap: Map<string, BABYLON.Color3>,
    onNodeCreated?: (mesh: BABYLON.Mesh, material: BABYLON.StandardMaterial, node: GraphNode) => void,
  ): void {
    let renderCount = 0;

    for (const node of nodes) {
      if (this.nodeMeshMap.has(node.id)) continue; // Already rendered

      const position = nodePositions.get(node.id) || BABYLON.Vector3.Zero();
      const color = fileColorMap.get(node.file || 'external') || new BABYLON.Color3(0.7, 0.7, 0.7);

      // Create node mesh via factory
      this.meshFactory.createNodeMesh(node, position, color, 0, (mesh, material) => {
        this.nodeMeshMap.set(node.id, mesh);
        mesh.parent = this.sceneRoot;
        mesh.position = position.clone();

        if (onNodeCreated) {
          onNodeCreated(mesh, material, node);
        }

        renderCount++;
      });
    }

    console.log(`📦 Rendered nodes: ${renderCount}`);
  }

public renderEdges(
    edges: GraphEdge[],
    nodeMeshMap: Map<string, BABYLON.Mesh>,
    _currentEdgeKinds: Map<string, GraphEdge['kind']>,
  ): void {
    // Edge rendering delegated to MeshFactory.createEdges() which is called
    // with full graph data from VRSceneManager - this method is a placeholder
    // for the rendering interface
    const edgeData = edges.map(e => ({
      from: e.from,
      to: e.to,
      kind: e.kind || 'call' as const,
    }));

    if (edgeData.length > 0 && nodeMeshMap.size > 0) {
      // Edges will be rendered via parent service
      console.log(`📊 Prepared ${edgeData.length} edges for rendering`);
    }
  }

public createFileBoxLabel(
    file: string,
    box: BABYLON.Mesh,
  ): BABYLON.Mesh | null {
    const labelTexture = new BABYLON.DynamicTexture(`label_${file}`, 512, this.scene, true);
    const ctx = labelTexture.getContext() as CanvasRenderingContext2D;

    // Draw label background and text
    ctx.fillStyle = 'rgba(40, 60, 80, 0.9)';
    ctx.fillRect(0, 0, 512, 128);
    ctx.fillStyle = '#ffffff';
    ctx.font = 'bold 32px monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(file, 256, 64);
    labelTexture.update();

    // Create label plane
    const labelPlane = BABYLON.MeshBuilder.CreatePlane(
      `label_plane_${file}`,
      { width: 4, height: 1 },
      this.scene,
    );
    labelPlane.parent = this.sceneRoot;
    labelPlane.position.copyFrom(box.position);
    labelPlane.position.y += box.scaling.y * 0.5 + 1;

    const labelMat = new BABYLON.StandardMaterial(`label_mat_${file}`, this.scene);
    labelMat.emissiveTexture = labelTexture;
    labelMat.disableLighting = true;
    labelMat.backFaceCulling = false;
    labelPlane.material = labelMat;

    this.fileBoxLabels.set(file, labelPlane);
    return labelPlane;
  }

public updateLabelTransforms(): void {
    for (const [file, label] of this.fileBoxLabels) {
      const box = this.fileBoxMeshes.get(file);
      if (!box) continue;

      label.position.copyFrom(box.position);
      label.position.y += box.scaling.y * 0.5 + 1;
    }

    for (const [dir, label] of this.directoryBoxLabels) {
      const box = this.directoryBoxMeshes.get(dir);
      if (!box) continue;

      label.position.copyFrom(box.position);
      label.position.y += box.scaling.y * 0.5 + 1;
    }
  }

public getNodeMeshMap(): Map<string, BABYLON.Mesh> {
    return this.nodeMeshMap;
  }

public getFileBoxMeshes(): Map<string, BABYLON.Mesh> {
    return this.fileBoxMeshes;
  }

public getDirectoryBoxMeshes(): Map<string, BABYLON.Mesh> {
    return this.directoryBoxMeshes;
  }

public populateCurrentEdges(edges: GraphEdge[]): Map<string, GraphEdge['kind']> {
    const edgeKinds = new Map<string, GraphEdge['kind']>();
    for (const edge of edges) {
      const key = `${edge.from}→${edge.to}`;
      edgeKinds.set(key, edge.kind ?? 'call');
    }
    return edgeKinds;
  }

public autosizeFileBoxes(
    _fileNodeCounts: Map<string, number>,
    nodeGroupBounds: Map<string, { min: BABYLON.Vector3; max: BABYLON.Vector3 }>,
  ): Map<string, BABYLON.Vector3> {
    const dimensions = new Map<string, BABYLON.Vector3>();

    for (const [file, bounds] of nodeGroupBounds) {
      const size = bounds.max.subtract(bounds.min);
      const padding = 4.0;
      const scaledSize = new BABYLON.Vector3(
        Math.max(8, size.x + padding),
        Math.max(8, size.y + padding),
        Math.max(8, size.z + padding),
      );
      dimensions.set(file, scaledSize);
    }

    return dimensions;
  }

async loadGraph(jsonPath: string = '/unitcircle/graph.json'): Promise<void> {
    try {
      const response = await fetch(jsonPath);
      if (!response.ok) {
        throw new Error(`Failed to load graph: ${response.statusText}`);
      }
      this.graphData = await response.json();
      if (this.graphData) {
        this.filteredNodes = [...this.graphData.nodes];
        this.filteredEdges = [...this.graphData.edges];
      }
      this.render();
    } catch (error) {
      this.showError(`Error loading graph: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

search(term: string): void {
    this.searchTerm = term.toLowerCase();
    this.applyFilters();
  }

filterByType(type: string): void {
    this.filterType = type;
    this.applyFilters();
  }

private applyFilters(): void {
    if (!this.graphData) return;

    this.filteredNodes = this.graphData.nodes.filter(node => {
      // Type filter
      if (this.filterType !== 'all' && node.type !== this.filterType) {
        return false;
      }

      // Search filter
      if (this.searchTerm) {
        const nodeId = 'id' in node ? node.id : '';
        const nodeName = 'name' in node ? node.name : '';
        const nodeFile = 'file' in node ? node.file : '';

        return (
          nodeId.toLowerCase().includes(this.searchTerm) ||
          nodeName.toLowerCase().includes(this.searchTerm) ||
          nodeFile.toLowerCase().includes(this.searchTerm)
        );
      }

      return true;
    });

    // Filter edges to only include visible nodes
    const visibleIds = new Set(this.filteredNodes.map(n => n.id));
    this.filteredEdges = this.graphData.edges.filter(
      edge => visibleIds.has(edge.from) && visibleIds.has(edge.to)
    );

    this.render();
  }

getStats() {
    if (!this.graphData) {
      return {
        totalNodes: 0,
        functions: 0,
        variables: 0,
        externalModules: 0,
        totalEdges: 0,
        lastUpdated: ''
      };
    }

    return {
      totalNodes: this.graphData.nodes.length,
      functions: this.graphData.nodes.filter(n => n.type === 'function').length,
      variables: this.graphData.nodes.filter(n => n.type === 'variable').length,
      externalModules: this.graphData.nodes.filter(n => n.type === 'external').length,
      totalEdges: this.graphData.edges.length,
      lastUpdated: this.graphData.lastUpdated
    };
  }

findCallsFrom(nodeId: string): FunctionCall[] {
    if (!this.graphData) return [];
    return this.graphData.edges.filter(edge => edge.from === nodeId);
  }

findCallsTo(nodeId: string): FunctionCall[] {
    if (!this.graphData) return [];
    return this.graphData.edges.filter(edge => edge.to === nodeId);
  }

getNode(nodeId: string): CodeNode | undefined {
    if (!this.graphData) return undefined;
    return this.graphData.nodes.find(n => n.id === nodeId);
  }

private renderNodesTable(): string {
    if (this.filteredNodes.length === 0) {
      return '<p class="no-results">No nodes match your search.</p>';
    }

    const nodeRows = this.filteredNodes
      .map(node => this.renderNodeRow(node))
      .join('');

    return `
      <table class="nodes-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Type</th>
            <th>File</th>
            <th>Line</th>
            <th>Exported</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          ${nodeRows}
        </tbody>
      </table>
    `;
  }

private renderNodeRow(node: CodeNode): string {
    const nodeId = node.id;
    const name = 'name' in node ? node.name : nodeId;
    const file = 'file' in node ? node.file : '—';
    const line = 'line' in node ? node.line : '—';
    const exported = 'isExported' in node ? (node.isExported ? '✅' : '❌') : '—';
    const typeColor = this.getTypeColor(node.type);

    let actions = '';
    if (node.type !== 'external') {
      const callsFrom = this.findCallsFrom(nodeId).length;
      const callsTo = this.findCallsTo(nodeId).length;
      actions = `<span class="calls-badge">${callsFrom} → ${callsTo}</span>`;
    }

    return `
      <tr class="node-row" data-node-id="${nodeId}">
        <td><code>${nodeId}</code></td>
        <td><strong>${name}</strong></td>
        <td><span class="type-badge" style="background-color: ${typeColor}">${node.type}</span></td>
        <td><code>${file}</code></td>
        <td>${line}</td>
        <td>${exported}</td>
        <td>${actions}</td>
      </tr>
    `;
  }

private renderEdgesTable(): string {
    if (this.filteredEdges.length === 0) {
      return '<p class="no-results">No edges match your search.</p>';
    }

    const edgeRows = this.filteredEdges
      .map(edge => this.renderEdgeRow(edge))
      .join('');

    return `
      <table class="edges-table">
        <thead>
          <tr>
            <th>From</th>
            <th>To</th>
            <th>From Type</th>
            <th>To Type</th>
          </tr>
        </thead>
        <tbody>
          ${edgeRows}
        </tbody>
      </table>
    `;
  }

private renderEdgeRow(edge: FunctionCall): string {
    const fromNode = this.getNode(edge.from);
    const toNode = this.getNode(edge.to);

    const fromName = fromNode && 'name' in fromNode ? fromNode.name : edge.from;
    const toName = toNode && 'name' in toNode ? toNode.name : edge.to;
    const fromType = fromNode?.type ?? 'unknown';
    const toType = toNode?.type ?? 'unknown';

    return `
      <tr class="edge-row">
        <td><strong>${fromName}</strong></td>
        <td><strong>${toName}</strong></td>
        <td><span class="type-badge" style="background-color: ${this.getTypeColor(fromType)}">${fromType}</span></td>
        <td><span class="type-badge" style="background-color: ${this.getTypeColor(toType)}">${toType}</span></td>
      </tr>
    `;
  }

private getTypeColor(type: string): string {
    const colors: { [key: string]: string } = {
      function: '#4A9EFF',
      variable: '#FFD700',
      external: '#00D4FF'
    };
    return colors[type] || '#808080';
  }

private setupEventListeners(): void {
    const searchInput = document.getElementById('search-input') as HTMLInputElement;
    const filterSelect = document.getElementById('filter-select') as HTMLSelectElement;
    const tabButtons = document.querySelectorAll('.tab-button');

    if (searchInput) {
      searchInput.addEventListener('input', (e) => {
        this.search((e.target as HTMLInputElement).value);
      });
    }

    if (filterSelect) {
      filterSelect.addEventListener('change', (e) => {
        this.filterByType((e.target as HTMLSelectElement).value);
      });
    }

    tabButtons.forEach(button => {
      button.addEventListener('click', () => {
        this.switchTab(button);
      });
    });
  }

private switchTab(button: Element): void {
    const tabName = button.getAttribute('data-tab');
    if (!tabName) return;

    // Update button states
    document.querySelectorAll('.tab-button').forEach(btn => {
      btn.classList.remove('active');
    });
    button.classList.add('active');

    // Update content visibility
    document.querySelectorAll('.tab-content').forEach(content => {
      content.classList.remove('active');
    });

    const tabContent = document.getElementById(`${tabName}-tab`);
    if (tabContent) {
      tabContent.classList.add('active');
    }
  }

private showError(message: string): void {
    const container = document.querySelector(this.containerSelector);
    if (container) {
      container.innerHTML = `<div class="error-message">❌ ${message}</div>`;
    }
  }

createFileBoxLabel(file: string, fileBox: BABYLON.Mesh): void {
    const fileMat = fileBox.material as BABYLON.StandardMaterial | null;
    const fileTint = fileMat?.diffuseColor ?? new BABYLON.Color3(0.2, 0.2, 0.2);
    const fileR = Math.max(0, Math.min(255, Math.floor(fileTint.r * 255)));
    const fileG = Math.max(0, Math.min(255, Math.floor(fileTint.g * 255)));
    const fileB = Math.max(0, Math.min(255, Math.floor(fileTint.b * 255)));

    const displayPath = toProjectRelativePath(file);
    const label = this.createBreadcrumbLabelAnchor(
      `filelabel_${file}`,
      this.buildBreadcrumbSegments('file', displayPath),
      `rgba(${fileR}, ${fileG}, ${fileB}, 0.84)`,
      'rgba(255, 255, 255, 0.92)',
      '#ffffff',
    );

    this.updateFileBoxLabelTransform(label, fileBox);
    this.state.fileBoxLabels.set(file, label);
    this.state.fileLabelLookup.set(displayPath, label);
  }

updateFileBoxLabelTransform(label: BABYLON.Mesh, fileBox: BABYLON.Mesh): void {
    fileBox.computeWorldMatrix(true);
    const bounds = fileBox.getBoundingInfo().boundingBox;
    const worldPos = new BABYLON.Vector3(
      bounds.centerWorld.x,
      bounds.maximumWorld.y + 8.1,
      bounds.centerWorld.z,
    );
    this.sceneRoot.computeWorldMatrix(true);
    label.position = BABYLON.Vector3.TransformCoordinates(
      worldPos,
      BABYLON.Matrix.Invert(this.sceneRoot.getWorldMatrix()),
    );
  }

createDirectoryBoxLabel(directoryPath: string, directoryBox: BABYLON.Mesh): void {
    const dirMat = directoryBox.material as BABYLON.StandardMaterial | null;
    const dirTint = dirMat?.diffuseColor ?? new BABYLON.Color3(0.10, 0.14, 0.18);
    const dirR = Math.max(0, Math.min(255, Math.floor(dirTint.r * 255)));
    const dirG = Math.max(0, Math.min(255, Math.floor(dirTint.g * 255)));
    const dirB = Math.max(0, Math.min(255, Math.floor(dirTint.b * 255)));

    const displayPath = toProjectRelativePath(directoryPath) || 'root';
    const label = this.createBreadcrumbLabelAnchor(
      `dirlabel_${directoryPath}`,
      this.buildBreadcrumbSegments('directory', displayPath),
      `rgba(${dirR}, ${dirG}, ${dirB}, 0.88)`,
      'rgba(128, 188, 255, 0.95)',
      '#f4fbff',
    );

    this.updateDirectoryBoxLabelTransform(label, directoryBox);
    this.state.directoryBoxLabels.set(directoryPath, label);
    this.state.directoryLabelLookup.set(displayPath, label);
  }

updateDirectoryBoxLabelTransform(label: BABYLON.Mesh, directoryBox: BABYLON.Mesh): void {
    directoryBox.computeWorldMatrix(true);
    const bounds = directoryBox.getBoundingInfo().boundingBox;
    const worldPos = new BABYLON.Vector3(
      bounds.centerWorld.x,
      bounds.maximumWorld.y + 9.2,
      bounds.centerWorld.z,
    );
    this.sceneRoot.computeWorldMatrix(true);
    label.position = BABYLON.Vector3.TransformCoordinates(
      worldPos,
      BABYLON.Matrix.Invert(this.sceneRoot.getWorldMatrix()),
    );
  }

refreshLabelTransformsIfScaleChanged(_force: boolean = false): void {
    for (const [file, label] of this.state.fileBoxLabels.entries()) {
      const fileBox = this.state.fileBoxMeshes.get(file);
      if (fileBox) this.updateFileBoxLabelTransform(label, fileBox);
    }
    for (const [dir, label] of this.state.directoryBoxLabels.entries()) {
      const dirBox = this.state.directoryBoxMeshes.get(dir);
      if (dirBox) this.updateDirectoryBoxLabelTransform(label, dirBox);
    }
  }

updateLabelDistanceScaling(): void {
    if (this.state.fileBoxLabels.size === 0 && this.state.directoryBoxLabels.size === 0) return;

    const activeCamera = this.scene.activeCamera;
    if (!activeCamera) return;

    const activeGlobal = (activeCamera as any).globalPosition as BABYLON.Vector3 | undefined;
    const cameraWorldPos = (activeGlobal && Number.isFinite(activeGlobal.x))
      ? activeGlobal
      : activeCamera.position;

    const renderWidth = Math.max(1, this.engine.getRenderWidth());
    const renderHeight = Math.max(1, this.engine.getRenderHeight());
    const aspect = renderWidth / renderHeight;
    const verticalFov = Math.max(0.25, this.getCameraFov());
    const horizontalFov = 2 * Math.atan(Math.tan(verticalFov * 0.5) * aspect);

    const fallbackBaseLabelWidth = 36.0;
    const readableMinScale = this.isInXR() ? 1.25 : 1.05;
    const hardMinScale = 0.35;
    const nearDistanceThreshold = this.isInXR() ? 45 : 90;
    const minViewportFraction = this.isInXR() ? 0.27 : 0.20;
    const maxViewportFraction = this.isInXR() ? 0.16 : 0.13;
    const maxScale = this.isInXR() ? 2.1 : 1.8;

    const applyScale = (label: BABYLON.Mesh): void => {
      const hierarchyBounds = label.getHierarchyBoundingVectors(true);
      const hierarchyWidth = Math.abs(hierarchyBounds.max.x - hierarchyBounds.min.x);
      const currentScale = Math.max(0.0001, label.scaling.x);
      const baseLabelWidth = Number.isFinite(hierarchyWidth) && hierarchyWidth > 0.001
        ? hierarchyWidth / currentScale
        : fallbackBaseLabelWidth;

      const distance = BABYLON.Vector3.Distance(cameraWorldPos, label.getAbsolutePosition());
      const minAngularWidth = horizontalFov * minViewportFraction;
      const maxAngularWidth = horizontalFov * maxViewportFraction;
      const minWorldWidthAtDistance = 2 * Math.max(0.01, distance) * Math.tan(minAngularWidth * 0.5);
      const maxWorldWidthAtDistance = 2 * Math.max(0.01, distance) * Math.tan(maxAngularWidth * 0.5);
      const floorScale = minWorldWidthAtDistance / baseLabelWidth;
      const viewportCapScale = maxWorldWidthAtDistance / baseLabelWidth;
      const effectiveMinScale = distance < nearDistanceThreshold ? hardMinScale : readableMinScale;

      const desiredScale = Math.max(effectiveMinScale, floorScale);
      const scale = Math.max(hardMinScale, Math.min(maxScale, viewportCapScale, desiredScale));
      if (Math.abs(label.scaling.x - scale) > 0.001) {
        label.scaling.copyFromFloats(scale, scale, scale);
      }
    };

    this.state.labelScaleState.clear();
    for (const label of this.state.fileBoxLabels.values()) applyScale(label);
    for (const label of this.state.directoryBoxLabels.values()) applyScale(label);
  }

setBreadcrumbAnchorInteractivity(labelAnchor: BABYLON.Mesh, enabled: boolean): void {
    labelAnchor.setEnabled(enabled);
    labelAnchor.isPickable = false;
    for (const child of labelAnchor.getChildMeshes(false)) {
      child.isPickable = enabled;
    }
  }

setLabelsVisibility(visible: boolean): void {
    this.state.labelsVisible = visible;
    if (!this.state.labelsVisible) {
      this.clearBreadcrumbHoverState();
    }
    for (const label of this.state.fileBoxLabels.values()) {
      this.setBreadcrumbAnchorInteractivity(label, this.state.labelsVisible);
    }
    for (const label of this.state.directoryBoxLabels.values()) {
      this.setBreadcrumbAnchorInteractivity(label, this.state.labelsVisible);
    }
  }

toggleLabelsVisibility(): void {
    this.setLabelsVisibility(!this.state.labelsVisible);
  }

clearBreadcrumbHoverState(): void {
    if (this.state.hoveredBreadcrumbChip) {
      const mat = (this.state.hoveredBreadcrumbChip as BABYLON.Mesh).material as BABYLON.StandardMaterial | null;
      if (mat) mat.emissiveColor = new BABYLON.Color3(1, 1, 1);
      this.state.hoveredBreadcrumbChip.renderOutline = false;
      this.state.hoveredBreadcrumbChip = null;
    }
  }

isBreadcrumbChipMesh(mesh: BABYLON.AbstractMesh): boolean {
    return (mesh as any).labelData !== undefined;
  }

findExactNavigationLabelTarget(kind: 'file' | 'directory', path: string): BABYLON.Mesh | null {
    const normalized = toProjectRelativePath(path) || path;
    if (!normalized) {
      return kind === 'directory' ? (this.state.directoryLabelLookup.get('root') ?? null) : null;
    }

    if (kind === 'file') {
      const hit = this.state.fileLabelLookup.get(normalized);
      if (hit) return hit;
      for (const [filePath, label] of this.state.fileBoxLabels.entries()) {
        if ((toProjectRelativePath(filePath) || filePath) === normalized) return label;
      }
      return null;
    }

    const dirHit = this.state.directoryLabelLookup.get(normalized);
    if (dirHit) return dirHit;
    for (const [dirPath, label] of this.state.directoryBoxLabels.entries()) {
      if ((toProjectRelativePath(dirPath) || dirPath) === normalized) return label;
    }
    return null;
  }

findNavigationLabelTarget(kind: 'file' | 'directory', path: string): BABYLON.Mesh | null {
    const normalized = toProjectRelativePath(path) || path;
    if (kind === 'file') {
      const hit = this.state.fileLabelLookup.get(normalized);
      if (hit) return hit;
      for (const [filePath, label] of this.state.fileBoxLabels.entries()) {
        if ((toProjectRelativePath(filePath) || filePath) === normalized) return label;
      }
      for (const [filePath, mesh] of this.state.fileBoxMeshes.entries()) {
        if ((toProjectRelativePath(filePath) || filePath) === normalized) return mesh;
      }
    }

    let currentPath = normalized;
    while (currentPath) {
      const dirHit = this.state.directoryLabelLookup.get(currentPath);
      if (dirHit) return dirHit;
      for (const [dirPath, label] of this.state.directoryBoxLabels.entries()) {
        if ((toProjectRelativePath(dirPath) || dirPath) === currentPath) return label;
      }
      for (const [dirPath, mesh] of this.state.directoryBoxMeshes.entries()) {
        if ((toProjectRelativePath(dirPath) || dirPath) === currentPath) return mesh;
      }
      const slashIndex = currentPath.lastIndexOf('/');
      currentPath = slashIndex >= 0 ? currentPath.slice(0, slashIndex) : '';
    }
    return null;
  }

resolveBreadcrumbNavigationTarget(
    kind: 'file' | 'directory',
    path: string,
    fallbackMesh: BABYLON.AbstractMesh,
  ): BABYLON.AbstractMesh {
    const exactLabelTarget = this.findExactNavigationLabelTarget(kind, path);
    if (exactLabelTarget) return exactLabelTarget;

    const normalized = toProjectRelativePath(path) || path;
    if (kind === 'file') {
      for (const [filePath, mesh] of this.state.fileBoxMeshes.entries()) {
        if ((toProjectRelativePath(filePath) || filePath) === normalized) return mesh;
      }
    } else {
      for (const [dirPath, mesh] of this.state.directoryBoxMeshes.entries()) {
        if ((toProjectRelativePath(dirPath) || dirPath) === normalized) return mesh;
      }
    }

    return this.findNavigationLabelTarget(kind, path) ?? fallbackMesh;
  }

buildBreadcrumbSegments(
    kind: 'file' | 'directory',
    fullPath: string,
  ): Array<{ text: string; kind: 'file' | 'directory'; path: string }> {
    const normalized = (fullPath || '').replace(/\\/g, '/');
    const parts = normalized.split('/').filter(Boolean);
    const segments: Array<{ text: string; kind: 'file' | 'directory'; path: string }> = [];

    let runningPath = '';
    for (let index = 0; index < parts.length; index++) {
      const part = parts[index];
      runningPath = runningPath ? `${runningPath}/${part}` : part;
      const isLast = index === parts.length - 1;
      segments.push({
        text: part,
        kind: kind === 'file' && isLast ? 'file' : 'directory',
        path: runningPath,
      });
    }

    if (segments.length === 0) {
      segments.push({ text: kind === 'directory' ? 'root' : fullPath, kind, path: fullPath });
    }

    return segments;
  }

private createLabelChip(
    name: string,
    text: string,
    fillStyle: string,
    strokeStyle: string,
    textStyle: string,
  ): { mesh: BABYLON.Mesh; width: number; height: number } {
    const fontSize = 440;
    const horizontalPadding = 220;
    const textureHeight = 720;

    const measureCanvas = document.createElement('canvas');
    const measureCtx = measureCanvas.getContext('2d') as CanvasRenderingContext2D;
    measureCtx.font = `bold ${fontSize}px monospace`;
    const textWidth = measureCtx.measureText(text).width;
    const textureWidth = Math.max(980, Math.ceil(textWidth + horizontalPadding * 2));

    const texture = new BABYLON.DynamicTexture(
      `${name}_texture`,
      { width: textureWidth, height: textureHeight },
      this.scene,
      false,
    );
    const ctx = texture.getContext() as CanvasRenderingContext2D;
    ctx.clearRect(0, 0, textureWidth, textureHeight);
    ctx.fillStyle = fillStyle;
    ctx.fillRect(0, 0, textureWidth, textureHeight);
    ctx.strokeStyle = strokeStyle;
    ctx.lineWidth = 8;
    ctx.strokeRect(8, 8, textureWidth - 16, textureHeight - 16);
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = textStyle;
    ctx.font = `bold ${fontSize}px monospace`;
    ctx.fillText(text, textureWidth / 2, textureHeight / 2 + 2);
    texture.update();

    const worldHeight = 9.6;
    const worldWidth = Math.max(17.0, worldHeight * (textureWidth / textureHeight));
    const mesh = BABYLON.MeshBuilder.CreatePlane(
      name,
      { width: worldWidth, height: worldHeight },
      this.scene,
    );
    const material = new BABYLON.StandardMaterial(`${name}_material`, this.scene);
    material.diffuseTexture = texture;
    material.emissiveColor = new BABYLON.Color3(1, 1, 1);
    material.specularColor = new BABYLON.Color3(0, 0, 0);
    material.backFaceCulling = false;
    material.useAlphaFromDiffuseTexture = true;
    material.disableLighting = true;
    material.disableDepthWrite = true;
    material.depthFunction = BABYLON.Constants.ALWAYS;
    mesh.material = material;
    mesh.renderingGroupId = 3;
    mesh.alwaysSelectAsActiveMesh = true;
    mesh.outlineColor = new BABYLON.Color3(0.95, 0.98, 1.0);
    mesh.outlineWidth = 0.16;

    const baseScaling = mesh.scaling.clone();
    mesh.actionManager = new BABYLON.ActionManager(this.scene);
    mesh.actionManager.registerAction(
      new BABYLON.ExecuteCodeAction(BABYLON.ActionManager.OnPointerOverTrigger, () => {
        mesh.renderOutline = true;
        material.emissiveColor = new BABYLON.Color3(1.2, 1.2, 1.2);
        mesh.scaling = baseScaling.scale(1.08);
      }),
    );
    mesh.actionManager.registerAction(
      new BABYLON.ExecuteCodeAction(BABYLON.ActionManager.OnPointerOutTrigger, () => {
        mesh.renderOutline = false;
        material.emissiveColor = new BABYLON.Color3(1, 1, 1);
        mesh.scaling = baseScaling.clone();
      }),
    );

    return { mesh, width: worldWidth, height: worldHeight };
  }

private withAdjustedAlpha(style: string, alpha: number): string {
    const rgbaMatch = style.match(/^rgba\((\d+),\s*(\d+),\s*(\d+),\s*([0-9.]+)\)$/i);
    if (!rgbaMatch) return style;
    const [, r, g, b] = rgbaMatch;
    return `rgba(${r}, ${g}, ${b}, ${alpha})`;
  }

private createBreadcrumbLabelAnchor(
    name: string,
    segments: Array<{ text: string; kind: 'file' | 'directory'; path: string }>,
    fillStyle: string,
    strokeStyle: string,
    textStyle: string,
  ): BABYLON.Mesh {
    const anchor = BABYLON.MeshBuilder.CreatePlane(
      `${name}_anchor`,
      { width: 1, height: 1 },
      this.scene,
    );
    anchor.visibility = 0;
    anchor.isPickable = false;
    anchor.parent = this.sceneRoot;
    anchor.scaling = new BABYLON.Vector3(1, 1, 1);
    anchor.billboardMode = BABYLON.Mesh.BILLBOARDMODE_ALL;
    anchor.renderingGroupId = 3;
    anchor.alwaysSelectAsActiveMesh = true;
    anchor.setEnabled(this.state.labelsVisible);

    const horizontalGap = 1.4;
    const verticalGap = 1.15;
    const maxRowWidth = 52;
    const rowHeight = 4.8;
    const rows: Array<Array<{ mesh: BABYLON.Mesh; width: number }>> = [];
    let currentRow: Array<{ mesh: BABYLON.Mesh; width: number }> = [];
    let currentRowWidth = 0;

    for (let index = 0; index < segments.length; index++) {
      const segment = segments[index];
      const isCurrentSegment = index === segments.length - 1;
      const chipFill = this.withAdjustedAlpha(fillStyle, isCurrentSegment ? 0.96 : 0.56);
      const chipStroke = this.withAdjustedAlpha(strokeStyle, isCurrentSegment ? 1.0 : 0.72);
      const chipText = isCurrentSegment ? textStyle : 'rgba(232, 238, 244, 0.82)';
      const chip = this.createLabelChip(`${name}_chip_${index}`, segment.text, chipFill, chipStroke, chipText);
      chip.mesh.parent = anchor;
      chip.mesh.isPickable = this.state.labelsVisible;
      (chip.mesh as any).labelData = { kind: segment.kind, path: segment.path };

      const widthWithGap = currentRow.length === 0 ? chip.width : chip.width + horizontalGap;
      if (currentRow.length > 0 && currentRowWidth + widthWithGap > maxRowWidth) {
        rows.push(currentRow);
        currentRow = [];
        currentRowWidth = 0;
      }

      currentRow.push({ mesh: chip.mesh, width: chip.width });
      currentRowWidth += currentRow.length === 1 ? chip.width : chip.width + horizontalGap;
    }

    if (currentRow.length > 0) rows.push(currentRow);

    const totalHeight = rows.length * rowHeight + Math.max(0, rows.length - 1) * verticalGap;
    rows.forEach((row, rowIndex) => {
      const rowWidth = row.reduce((sum, c, i) => sum + c.width + (i > 0 ? horizontalGap : 0), 0);
      let cursorX = -rowWidth * 0.5;
      const y = totalHeight * 0.5 - rowIndex * (rowHeight + verticalGap) - rowHeight * 0.5;
      row.forEach((chip) => {
        chip.mesh.position.x = cursorX + chip.width * 0.5;
        chip.mesh.position.y = y;
        chip.mesh.position.z = 0;
        cursorX += chip.width + horizontalGap;
      });
    });

    return anchor;
  }

